    def test_source_verification_materializes_cited_sources_without_private_text(self) -> None:
        event = self.engine.generate(
            "How should AI prove attribution?",
            gross_revenue=Decimal("1.00"),
        )
        receipt = make_attribution_receipt(
            event,
            issued_at="2026-05-29T00:00:11Z",
            signing_secret="secret",
        )
        trace = make_trace_exchange(event, receipt=receipt)
        card = make_answer_provenance_card(
            event,
            receipt=receipt,
            trace=trace,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:11Z",
            signing_secret="secret",
        )
        report = make_source_verification_report(
            event,
            self.engine,
            answer_card=card,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:11Z",
            signing_secret="secret",
        )

        self.assertEqual(
            verify_source_verification_report(
                event,
                self.engine,
                report,
                answer_card=card,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(
            report["report_version"],
            "rdllm-source-verification-report/v1",
        )
        self.assertEqual(report["summary"]["status"], "verified")
        self.assertTrue(report["summary"]["all_sources_materialized"])
        self.assertTrue(report["summary"]["all_supported_claims_materialized"])
        self.assertTrue(report["summary"]["answer_card_bound"])
        self.assertTrue(all(source["materialized"] for source in report["sources"]))
        self.assertTrue(
            all(
                claim["materialized"]
                for claim in report["claims"]
                if claim["supported"]
            )
        )
        report_json = canonical_json(report)
        self.assertNotIn(event.prompt, report_json)
        self.assertNotIn(event.answer_text, report_json)
        for source in event.source_references:
            self.assertNotIn(source.quote, report_json)
        for claim in event.claim_support:
            self.assertNotIn(claim.claim, report_json)
            self.assertNotIn(claim.evidence_text, report_json)

        tampered = deepcopy(report)
        tampered["sources"] = deepcopy(tampered["sources"])
        tampered["sources"][0]["content_hash_reproducible"] = False
        errors = verify_source_verification_report(
            event,
            self.engine,
            tampered,
            answer_card=card,
            signing_secret="secret",
        )
        self.assertIn("source verification report hash is not reproducible", errors)
        self.assertTrue(any("sources does not match" in error for error in errors))

        tampered_event_data = event.to_dict()
        tampered_event_data["claim_support"][0]["evidence_text"] = "fabricated evidence"
        tampered_event = UsageEvent.from_dict(tampered_event_data)
        event_errors = verify_source_verification_report(
            tampered_event,
            self.engine,
            report,
            answer_card=card,
            signing_secret="secret",
        )
        self.assertTrue(
            any("claims does not match" in error for error in event_errors)
            or any("status is not verified" in error for error in event_errors)
        )

