        tampered_card["sources"][0]["title"] = "Fabricated Title"
        card_errors = verify_source_confidence_report(
            report,
            answer_card=tampered_card,
            source_verification_report=source_report,
            creator_license_contract=license_contract,
            signing_secret="secret",
        )
        self.assertTrue(any("public artifacts" in error for error in card_errors))

