    def test_counterevidence_report_blocks_unaddressed_contradictions(self) -> None:
        def proof_stack(engine: RoyaltyDrivenLLM, event: UsageEvent):
            receipt = make_attribution_receipt(
                event,
                issued_at="2026-05-29T00:00:12Z",
                signing_secret="secret",
            )
            trace = make_trace_exchange(event, receipt=receipt)
            card = make_answer_provenance_card(
                event,
                receipt=receipt,
                trace=trace,
                issuer="test-issuer",
                created_at="2026-05-29T00:00:12Z",
                signing_secret="secret",
            )
            source_report = make_source_verification_report(
                event,
                engine,
                answer_card=card,
                issuer="test-issuer",
                created_at="2026-05-29T00:00:12Z",
                signing_secret="secret",
            )
            license_contract = make_creator_license_contract(
                creators=engine.creators,
                works=engine.works,
                issuer="test-issuer",
                provider="provider:test",
                effective_at="2026-05-29T00:00:12Z",
                created_at="2026-05-29T00:00:12Z",
                signing_secret="secret",
            )
            source_confidence = make_source_confidence_report(
                answer_card=card,
                source_verification_report=source_report,
                creator_license_contract=license_contract,
                issuer="test-issuer",
                created_at="2026-05-29T00:00:12Z",
                signing_secret="secret",
            )
            envelope = make_response_envelope(
                event,
                answer_card=card,
                source_verification_report=source_report,
                source_confidence_report=source_confidence,
                creator_license_contract=license_contract,
                public_receipt=public_receipt(receipt),
                issuer="test-issuer",
                created_at="2026-05-29T00:00:12Z",
                signing_secret="secret",
            )
            footer_contract = make_citation_footer_contract(
                response_envelope=envelope,
                issuer="test-issuer",
                created_at="2026-05-29T00:00:12Z",
                signing_secret="secret",
            )
            snapshots = [
                {
                    "source_uri": source.source_uri,
                    "canonical_uri": source.source_uri,
                    "archived_uri": f"https://archive.example.org/{source.work_id}/{source.chunk_id}",
                    "retrieved_at": "2026-05-29T00:00:12Z",
                    "http_status": 200,
                    "media_type": "text/plain",
                    "retrieval_method": "provider_snapshot",
                    "resolver_id": "resolver:test",
                    "work_id": source.work_id,
                    "chunk_id": source.chunk_id,
                    "body_text": engine.chunk_by_id[source.chunk_id].text,
                }
                for source in event.source_references
            ]
            source_availability = make_source_availability_report(
                event,
                engine,
                snapshots,
                answer_card=card,
                source_verification_report=source_report,
                citation_footer_contract=footer_contract,
                issuer="test-issuer",
                created_at="2026-05-29T00:00:12Z",
                signing_secret="secret",
            )
            evidence_sufficiency = make_evidence_sufficiency_report(
                event,
                engine,
                answer_card=card,
                source_verification_report=source_report,
                source_availability_report=source_availability,
                citation_footer_contract=footer_contract,
                issuer="test-issuer",
                created_at="2026-05-29T00:00:12Z",
                signing_secret="secret",
            )
            return card, source_report, source_availability, evidence_sufficiency, footer_contract

        event = self.engine.generate(
            "How should AI prove attribution?",
            gross_revenue=Decimal("1.00"),
        )
        card, source_report, source_availability, evidence_sufficiency, footer_contract = proof_stack(
            self.engine,
            event,
        )
        report = make_counterevidence_report(
            event,
            self.engine,
            answer_card=card,
            source_verification_report=source_report,
            source_availability_report=source_availability,
            evidence_sufficiency_report=evidence_sufficiency,
            citation_footer_contract=footer_contract,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:12Z",
            signing_secret="secret",
        )

        self.assertEqual(
            verify_counterevidence_report(
                report,
                event,
                self.engine,
                answer_card=card,
                source_verification_report=source_report,
                source_availability_report=source_availability,
                evidence_sufficiency_report=evidence_sufficiency,
                citation_footer_contract=footer_contract,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(
            report["report_version"],
            "rdllm-counterevidence-adjudication-report/v1",
        )
        self.assertEqual(report["summary"]["target_certification_level"], "RDLLM-L57")
        self.assertEqual(report["summary"]["status"], "verified")
        self.assertEqual(report["summary"]["unaddressed_counterevidence_count"], 0)
        self.assertTrue(report["summary"]["all_claims_counterevidence_adjudicated"])

        conflict_engine = RoyaltyDrivenLLM(
            creators=[
                Creator("pro", "Pro Creator", "acct_pro"),
                Creator("con", "Con Creator", "acct_con"),
            ],
            works=[
                Work(
                    "creator-payment-positive",
                    "pro",
                    "Creator Payment Positive",
                    "Royalty driven LLMs pay creators when registered content supports generated answers.",
                ),
                Work(
                    "creator-payment-negative",
                    "con",
                    "Creator Payment Negative",
                    "Royalty driven LLMs do not pay creators when registered content supports generated answers.",
                ),
            ],
            top_k=1,
        )
        conflict_event = conflict_engine.attribute_text(
            "Can royalty driven LLMs pay creators for supported generated answers?",
            "Royalty driven LLMs pay creators when registered content supports generated answers.",
            gross_revenue=Decimal("1.00"),
        )
        (
            conflict_card,
            conflict_source_report,
            conflict_availability,
            conflict_evidence_sufficiency,
            conflict_footer,
        ) = proof_stack(conflict_engine, conflict_event)
        conflict_report = make_counterevidence_report(
            conflict_event,
            conflict_engine,
            answer_card=conflict_card,
            source_verification_report=conflict_source_report,
            source_availability_report=conflict_availability,
            evidence_sufficiency_report=conflict_evidence_sufficiency,
            citation_footer_contract=conflict_footer,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:12Z",
            signing_secret="secret",
        )
        self.assertEqual(conflict_report["summary"]["status"], "failed")
        self.assertGreater(
            conflict_report["summary"]["unaddressed_counterevidence_count"],
            0,
        )
        self.assertTrue(
            any(
                "unaddressed counterevidence" in issue
                for issue in conflict_report["issues"]
            )
        )

        report_json = canonical_json(report)
        self.assertNotIn(event.prompt, report_json)
        self.assertNotIn(event.answer_text, report_json)
        for claim in event.claim_support:
            self.assertNotIn(claim.claim, report_json)
            self.assertNotIn(claim.evidence_text, report_json)
        for chunk in self.engine.chunks:
            self.assertNotIn(chunk.text, report_json)

        tampered = deepcopy(report)
        tampered["claims"] = deepcopy(tampered["claims"])
        tampered["claims"][0] = dict(tampered["claims"][0])
        tampered["claims"][0]["unaddressed_counterevidence_count"] = 1
        errors = verify_counterevidence_report(
            tampered,
            event,
            self.engine,
            answer_card=card,
            source_verification_report=source_report,
            source_availability_report=source_availability,
            evidence_sufficiency_report=evidence_sufficiency,
            citation_footer_contract=footer_contract,
            signing_secret="secret",
        )
        self.assertTrue(any("hash" in error or "replay" in error for error in errors))

