    def test_attribution_exchange_manifest_relays_cross_provider_proofs(self) -> None:
        event = self.engine.generate(
            "How should AI prove attribution?",
            gross_revenue=Decimal("1.00"),
        )
        ledger = RoyaltyLedger()
        ledger.record(event)
        receipt = make_attribution_receipt(
            event,
            issuer="test-issuer",
            issued_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        trace = make_trace_exchange(event, receipt=receipt)
        card = make_answer_provenance_card(
            event,
            receipt=receipt,
            trace=trace,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        source_report = make_source_verification_report(
            event,
            self.engine,
            answer_card=card,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        license_contract = make_creator_license_contract(
            creators=self.engine.creators,
            works=self.engine.works,
            issuer="test-issuer",
            provider="provider:test",
            created_at="2026-05-29T00:00:15Z",
            effective_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        source_confidence = make_source_confidence_report(
            answer_card=card,
            source_verification_report=source_report,
            creator_license_contract=license_contract,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        certification = {
            "certification_version": "rdllm-certification/v1",
            "suite": "rdllm-reference-conformance",
            "issued_at": "2026-05-29T00:00:15Z",
            "summary": {
                "status": "passed",
                "case_count": 38,
                "passed": 38,
                "failed": 0,
                "score": 1.0,
                "highest_level": "RDLLM-L37",
            },
            "levels": {},
            "cases": [],
        }
        certification["report_hash"] = hash_payload(certification)
        provider_card = make_provider_attribution_card(
            ledger.to_dict(),
            certification_report=certification,
            issuer="test-issuer",
            provider="provider:test",
            model_id="model:test",
            model_version="2026-05",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        base_envelope = make_response_envelope(
            event,
            answer_card=card,
            source_verification_report=source_report,
            source_confidence_report=source_confidence,
            creator_license_contract=license_contract,
            public_receipt=public_receipt(receipt),
            provider_card=provider_card,
            certification_report=certification,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        footer_contract = make_citation_footer_contract(
            response_envelope=base_envelope,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        envelope = make_response_envelope(
            event,
            answer_card=card,
            source_verification_report=source_report,
            source_confidence_report=source_confidence,
            creator_license_contract=license_contract,
            citation_footer_contract=footer_contract,
            public_receipt=public_receipt(receipt),
            provider_card=provider_card,
            certification_report=certification,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        profile = make_integration_profile(
            provider_card=provider_card,
            certification_report=certification,
            response_envelope=envelope,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        semantic_inputs = [
            {
                "input_id": "external_provenance_answer",
                "prompt": "How should provenance answers be sourced?",
                "output": (
                    "Every royalty bearing AI answer should have a provenance record. "
                    "The record should include source identifiers, content hashes, "
                    "retrieval scores, output citations, payout weights, and an "
                    "event hash that allows auditors to replay the attribution."
                ),
            },
            {
                "input_id": "unmatched_weather_note",
                "prompt": "What did the local report say?",
                "output": "A late storm moved over the harbor after sunset.",
            },
        ]
        semantic_report = make_semantic_text_attribution_report(
            self.engine,
            semantic_inputs,
            gross_revenue=Decimal("1.00"),
            creator_pool_rate=Decimal("0.55"),
            accept_threshold=0.20,
            min_margin=0.02,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        license_contract = make_creator_license_contract(
            creators=self.engine.creators,
            works=self.engine.works,
            issuer="test-issuer",
            provider="provider:test",
            created_at="2026-05-29T00:00:15Z",
            effective_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        assurance = make_assurance_bundle(
            [
                ("certification", "certification_report", certification),
                ("integration_profile", "integration_profile", profile),
                ("response_envelope", "response_envelope", envelope),
                ("answer_card", "answer_provenance_card", card),
                ("source_verification", "source_verification_report", source_report),
                ("source_confidence", "source_confidence_report", source_confidence),
                ("citation_footer", "citation_footer_contract", footer_contract),
                ("provider_card", "provider_attribution_card", provider_card),
                ("semantic_text", "semantic_text_attribution_report", semantic_report),
                (
                    "creator_license_contract",
                    "creator_license_contract",
                    license_contract,
                ),
                ("receipt", "attribution_receipt", receipt),
                ("trace", "trace_exchange", trace),
            ],
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        discovery = make_discovery_manifest(
            provider_card=provider_card,
            certification_report=certification,
            integration_profile=profile,
            response_envelope=envelope,
            assurance_bundle=assurance,
            semantic_text_attribution_report=semantic_report,
            creator_license_contract=license_contract,
            source_confidence_report=source_confidence,
            citation_footer_contract=footer_contract,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        exchange = make_attribution_exchange_manifest(
            provider_card=provider_card,
            certification_report=certification,
            integration_profile=profile,
            discovery_manifest=discovery,
            response_envelope=envelope,
            assurance_bundle=assurance,
            semantic_text_attribution_report=semantic_report,
            creator_license_contract=license_contract,
            source_confidence_report=source_confidence,
            citation_footer_contract=footer_contract,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )

        self.assertEqual(
            verify_attribution_exchange_manifest(
                exchange,
                provider_card=provider_card,
                certification_report=certification,
                integration_profile=profile,
                discovery_manifest=discovery,
                response_envelope=envelope,
                assurance_bundle=assurance,
                semantic_text_attribution_report=semantic_report,
                creator_license_contract=license_contract,
                source_confidence_report=source_confidence,
                citation_footer_contract=footer_contract,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(exchange["exchange_version"], "rdllm-attribution-exchange/v1")
        self.assertEqual(exchange["summary"]["status"], "ready")
