    def test_lineage_report_routes_derivative_royalties_upstream(self) -> None:
        original_creator = Creator("creator_original", "Original Writer", "acct_original")
        curator = Creator("creator_curator", "Summary Curator", "acct_curator")
        original = Work(
            work_id="work_original",
            creator_id=original_creator.creator_id,
            title="Original Climate Note",
            content=(
                "The original climate note says attribution systems should preserve "
                "source lineage across summaries and derived datasets."
            ),
            source_uri="https://example.test/original-climate-note",
        )
        derived = Work(
            work_id="work_summary",
            creator_id=curator.creator_id,
            title="Derived Climate Summary",
            content=(
                "Derived climate summary: attribution systems preserve source "
                "lineage across summaries."
            ),
            source_uri="https://example.test/derived-climate-summary",
            derived_from=(
                {
                    "work_id": original.work_id,
                    "weight": 1.0,
                    "relation": "summarizes",
                    "source_uri": original.source_uri,
                    "content_hash": stable_hash(original.content),
                },
            ),
        )
        engine = RoyaltyDrivenLLM(
            [original_creator, curator],
            [original, derived],
            top_k=1,
        )
        event = engine.attribute_text(
            "What does the derived climate summary say?",
            "Derived climate summary: attribution systems preserve source lineage across summaries.",
            gross_revenue=Decimal("1.00"),
        )
        report = make_lineage_report(
            event,
            works=engine.works,
            creators=engine.creators,
            pass_through_rate=Decimal("0.30"),
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )

        self.assertEqual(
            verify_lineage_report(
                report,
                event,
                works=engine.works,
                creators=engine.creators,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(report["report_version"], "rdllm-lineage-report/v1")
        self.assertEqual(report["summary"]["status"], "ready")
        self.assertTrue(report["summary"]["payout_conserved"])
        self.assertGreaterEqual(report["summary"]["derivative_source_count"], 1)
        self.assertGreaterEqual(report["summary"]["upstream_obligation_count"], 1)
        self.assertTrue(
            any(
                item["recipient_creator_id"] == original_creator.creator_id
                and Decimal(item["payout"]) > Decimal("0")
                for item in report["settlement_obligations"]
            )
        )
        self.assertTrue(
            any(
                item["recipient_creator_id"] == curator.creator_id
                and Decimal(item["payout"]) > Decimal("0")
                for item in report["settlement_obligations"]
            )
        )
        report_json = canonical_json(report)
        self.assertNotIn(original.content, report_json)
        self.assertNotIn(derived.content, report_json)
        self.assertNotIn(event.prompt, report_json)

        tampered = deepcopy(report)
        tampered["settlement_obligations"] = [
            dict(item) for item in tampered["settlement_obligations"]
        ]
        tampered["settlement_obligations"][0]["payout"] = "0.000001"
        errors = verify_lineage_report(
            tampered,
            event,
            works=engine.works,
            creators=engine.creators,
            signing_secret="secret",
        )
        self.assertTrue(any("hash" in error or "settlement" in error for error in errors))

    def test_transitive_attribution_routes_copied_output_reuse_upstream(self) -> None:
        upstream_event = self.engine.generate(
            "How should AI prove attribution?",
            gross_revenue=Decimal("1.00"),
        )
        ledger = RoyaltyLedger()
        ledger.record(upstream_event)
        receipt = make_attribution_receipt(
            upstream_event,
            issuer="test-issuer",
            issued_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        trace = make_trace_exchange(upstream_event, receipt=receipt)
        answer_card = make_answer_provenance_card(
            upstream_event,
            receipt=receipt,
            trace=trace,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        source_report = make_source_verification_report(
            upstream_event,
            self.engine,
            answer_card=answer_card,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        certification = {
            "certification_version": "rdllm-certification/v1",
            "suite": "rdllm-reference-certification",
            "issued_at": "2026-05-29T00:00:00Z",
            "summary": {
                "status": "passed",
                "case_count": 42,
                "passed": 42,
                "failed": 0,
                "score": 1.0,
                "highest_level": "RDLLM-L41",
            },
            "levels": {},
            "cases": [],
        }
        certification["report_hash"] = hash_payload(certification)
        provider_card = make_provider_attribution_card(
            ledger.to_dict(),
            certification_report=certification,
            issuer="test-issuer",
            provider="provider:upstream",
            model_id="model:test",
            model_version="2026-05",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )
        envelope = make_response_envelope(
            upstream_event,
            answer_card=answer_card,
            source_verification_report=source_report,
            public_receipt=public_receipt(receipt),
            provider_card=provider_card,
            certification_report=certification,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:15Z",
            signing_secret="secret",
        )

        def hashable_capsule(capsule: dict[str, object]) -> dict[str, object]:
            payload = {
                key: value
                for key, value in capsule.items()
                if key not in {"capsule_hash", "signature"}
            }
            surfaces = deepcopy(payload.get("portable_surfaces", {}))
            if isinstance(surfaces, dict):
                headers = surfaces.get("http_headers")
                if isinstance(headers, dict):
                    headers.pop("RDLLM-Capsule-Hash", None)
                payload["portable_surfaces"] = surfaces
            return payload

        subject = {
            "content_kind": "text",
            "event_id": envelope["response"]["event_id"],
            "event_hash": envelope["response"]["event_hash"],
            "rendered_output_hash": envelope["response"]["rendered_output_hash"],
            "answer_hash": envelope["response"]["answer_hash"],
            "source_label_root": envelope["commitments"]["footer_label_root"],
            "claim_span_root": envelope["commitments"]["footer_span_root"],
            "source_count": envelope["summary"]["source_count"],
            "claim_count": envelope["summary"]["claim_count"],
        }
        commitments = {
            "subject_hash": hash_payload(subject),
            "response_envelope_hash": envelope["envelope_hash"],
        }
        capsule_id = f"rdllm-cap-{hash_payload(commitments)[:24]}"
        text_footer = (
            f"RDLLM attribution capsule: {capsule_id} | verify "
            f"/.well-known/rdllm/attribution-capsule.json | "
            f"output_hash={subject['rendered_output_hash'][:16]} | handshake=test"
        )
        capsule = {
            "capsule_version": "rdllm-attribution-capsule/v1",
            "issuer": "test-issuer",
            "created_at": "2026-05-29T00:00:15Z",
            "subject": subject,
            "portable_surfaces": {
                "capsule_id": capsule_id,
                "text_footer": text_footer,
                "markdown_comment": "",
                "http_headers": {
                    "RDLLM-Capsule-ID": capsule_id,
                    "RDLLM-Capsule-Hash": "",
                    "RDLLM-Output-Hash": subject["rendered_output_hash"],
                },
            },
            "commitments": commitments,
            "summary": {
                "status": "ready",
                "capsule_id": capsule_id,
            },
            "privacy": {
                "prompt_text_disclosed": False,
                "answer_text_disclosed": False,
                "source_text_disclosed": False,
            },
        }
        capsule["capsule_hash"] = hash_payload(hashable_capsule(capsule))
        capsule["signature"] = {
            "algorithm": "UNSIGNED",
            "issuer": "test-issuer",
            "value": "",
        }
        capsule["portable_surfaces"]["http_headers"]["RDLLM-Capsule-Hash"] = capsule[
            "capsule_hash"
        ]
        copied_output = f"{envelope['response']['rendered_output']}\n\n{text_footer}"
        downstream_event = self.engine.attribute_text(
            "Downstream use of a copied RDLLM output",
            copied_output,
            gross_revenue=Decimal("1.00"),
        )
        report = make_transitive_attribution_report(
            upstream_capsule=capsule,
            upstream_response_envelope=envelope,
            downstream_event=downstream_event,
            copied_output=copied_output,
            pass_through_rate=Decimal("0.70"),
            issuer="test-issuer",
            created_at="2026-05-29T00:00:16Z",
            signing_secret="secret",
        )

        self.assertEqual(
            verify_transitive_attribution_report(
                report,
                upstream_capsule=capsule,
                upstream_response_envelope=envelope,
                downstream_event=downstream_event,
                copied_output=copied_output,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(
            report["report_version"],
            "rdllm-transitive-attribution-report/v1",
        )
        self.assertEqual(report["summary"]["status"], "ready")
        self.assertEqual(report["summary"]["target_certification_level"], "RDLLM-L42")
        self.assertTrue(report["summary"]["anti_laundering_enforced"])
        self.assertTrue(report["summary"]["payout_conserved"])
        self.assertEqual(
            report["summary"]["transitive_obligation_count"],
            report["summary"]["upstream_source_count"],
        )
        self.assertGreater(report["summary"]["upstream_source_count"], 0)
        self.assertEqual(
            Decimal(report["summary"]["transitive_pool"]),
            Decimal("0.39"),
        )
        report_json = canonical_json(report)
        self.assertNotIn(copied_output, report_json)
        self.assertNotIn(upstream_event.output, report_json)
        self.assertNotIn(downstream_event.prompt, report_json)

        missing_marker_errors = verify_transitive_attribution_report(
            report,
            upstream_capsule=capsule,
            upstream_response_envelope=envelope,
            downstream_event=downstream_event,
            copied_output=envelope["response"]["rendered_output"],
            signing_secret="secret",
        )
        self.assertTrue(
            any("does not match evidence" in error or "status" in error for error in missing_marker_errors)
        )
        tampered = deepcopy(report)
        tampered["settlement_obligations"] = [
            dict(item) for item in tampered["settlement_obligations"]
        ]
        tampered["settlement_obligations"][0]["payout"] = "0.00"
        errors = verify_transitive_attribution_report(
            tampered,
            upstream_capsule=capsule,
            upstream_response_envelope=envelope,
            downstream_event=downstream_event,
            copied_output=copied_output,
            signing_secret="secret",
        )
        self.assertTrue(any("hash" in error or "evidence" in error for error in errors))

