    def test_live_emission_transparency_requires_log_inclusion(self) -> None:
        live_witness = json.loads(
            (ROOT / "artifacts" / "live_emission_witness.json").read_text(
                encoding="utf-8"
            )
        )
        prefix_log = make_live_emission_transparency_log(
            live_witness,
            log_id="live-prefix",
            include_attestations=False,
        )
        latest_log = make_live_emission_transparency_log(
            live_witness,
            log_id="live-latest",
            existing_entries=prefix_log["entries"],
        )
        report = make_live_emission_transparency_report(
            live_emission_witness=live_witness,
            transparency_logs=[("live-prefix", prefix_log), ("live-latest", latest_log)],
            issuer="test",
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(
            verify_live_emission_transparency_report(
                report,
                live_emission_witness=live_witness,
                transparency_logs=[
                    ("live-prefix", prefix_log),
                    ("live-latest", latest_log),
                ],
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(report["summary"]["target_certification_level"], "RDLLM-L85")
        self.assertEqual(report["summary"]["status"], "ready")
        self.assertTrue(report["summary"]["live_emission_transparency_included"])
        self.assertEqual(report["summary"]["missing_subject_count"], 0)
        self.assertEqual(report["summary"]["required_subject_count"], 7)

        missing = make_live_emission_transparency_report(
            live_emission_witness=live_witness,
            transparency_logs=[("report-only", prefix_log)],
            issuer="test",
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(missing["summary"]["status"], "failed")
        self.assertFalse(missing["checks"]["required_subjects_in_latest_log"])

        tampered = deepcopy(latest_log)
        tampered["root"] = hash_payload("tampered-live-log-root")
        tampered_report = make_live_emission_transparency_report(
            live_emission_witness=live_witness,
            transparency_logs=[("tampered", tampered)],
            issuer="test",
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(tampered_report["summary"]["status"], "failed")
        self.assertFalse(tampered_report["checks"]["transparency_roots_reproducible"])
        self.assertNotIn('"chunk_text":', canonical_json(report))

