    def test_claim_source_attribution_replays_footer_and_visual_evidence(self) -> None:
        attribution_input = {
            "event": {
                "event_id": "event:test-claim-source",
                "prompt_text": "What controls does the answer need?",
                "response_text": (
                    "The answer needs claim-level source footers and visual "
                    "evidence anchors for credited slides."
                ),
            },
            "claims": [
                {
                    "claim_id": "claim:footer",
                    "claim_text": "The answer needs claim-level source footers.",
                    "required_evidence_phrases": ["claim-level source footers"],
                    "expected_source_ids": ["source:footer"],
                    "forbidden_source_ids": ["source:decoy"],
                },
                {
                    "claim_id": "claim:visual",
                    "claim_text": "Credited slides need visual evidence anchors.",
                    "required_evidence_phrases": ["visual evidence anchors"],
                    "expected_source_ids": ["source:slide"],
                },
            ],
            "candidate_sources": [
                {
                    "source_id": "source:footer",
                    "work_id": "work:footer",
                    "chunk_id": "chunk:footer",
                    "creator_id": "creator:footer",
                    "creator_name": "Footer Creator",
                    "title": "Footer Policy",
                    "source_uri": "https://example.test/footer",
                    "content": "The policy says the answer needs claim-level source footers.",
                    "modality": "text",
                },
                {
                    "source_id": "source:decoy",
                    "work_id": "work:decoy",
                    "chunk_id": "chunk:decoy",
                    "creator_id": "creator:decoy",
                    "creator_name": "Decoy Creator",
                    "title": "Topical Decoy",
                    "source_uri": "https://example.test/decoy",
                    "content": "The policy talks about answers, claims, sources, and footers without requiring the cited rule.",
                    "document_role": "anti_document",
                    "modality": "text",
                },
                {
                    "source_id": "source:slide",
                    "work_id": "work:slide",
                    "chunk_id": "chunk:slide",
                    "creator_id": "creator:slide",
                    "creator_name": "Slide Creator",
                    "title": "Visual Policy Slide",
                    "source_uri": "https://example.test/slide",
                    "content": "Credited slides need visual evidence anchors.",
                    "modality": "slide",
                    "visual_regions": [
                        {
                            "region_id": "region:anchor",
                            "page": 1,
                            "x": 0.1,
                            "y": 0.2,
                            "width": 0.4,
                            "height": 0.2,
                            "region_text": "Credited slides need visual evidence anchors.",
                        }
                    ],
                },
            ],
            "qna_nuggets": [
                {
                    "nugget_id": "nugget:footer",
                    "source_id": "source:footer",
                    "question": "What does the answer need?",
                    "answer": "It needs claim-level source footers.",
                }
            ],
        }
        report = make_claim_source_attribution_report(
            attribution_input,
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(
            verify_claim_source_attribution_report(
                report,
                attribution_input,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(report["summary"]["target_certification_level"], "RDLLM-L87")
        self.assertEqual(report["summary"]["status"], "ready")
        self.assertEqual(report["summary"]["grounded_claim_count"], 2)
        self.assertEqual(report["footer"]["source_row_count"], 2)
        self.assertTrue(report["checks"]["visual_sources_have_region_commitments"])
        self.assertTrue(report["checks"]["attribution_credit_conserved_per_grounded_claim"])
        self.assertGreaterEqual(report["summary"]["anti_document_rejected_count"], 1)

        drifted = deepcopy(attribution_input)
        drifted["candidate_sources"][0]["content"] = "This source no longer supports the claim."
        self.assertTrue(
            verify_claim_source_attribution_report(
                report,
                drifted,
                signing_secret="secret",
            )
        )

        missing_visual = deepcopy(attribution_input)
        missing_visual["candidate_sources"][2]["visual_regions"] = []
        missing_visual_report = make_claim_source_attribution_report(
            missing_visual,
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(missing_visual_report["summary"]["status"], "failed")
        self.assertFalse(
            missing_visual_report["checks"]["visual_sources_have_region_commitments"]
        )
        rendered = canonical_json(report)
        self.assertNotIn("The policy says the answer needs claim-level source footers.", rendered)
        self.assertNotIn("Credited slides need visual evidence anchors.", rendered)
        self.assertNotIn("What controls does the answer need?", rendered)

    def test_evidence_utility_attribution_rejects_spurious_and_drifted_citations(
        self,
    ) -> None:
        utility_input = {
            "event": {
                "event_id": "event:test-utility",
                "prompt_text": "What citations should receive credit?",
                "response_text": (
                    "Credited citations need current-turn retrieval and causal utility."
                ),
            },
            "claims": [
                {
                    "claim_id": "claim:utility",
                    "claim_text": "Credited citations need current-turn retrieval and causal utility.",
                    "expected_source_ids": ["source:utility"],
                }
            ],
            "candidate_sources": [
                {
                    "source_id": "source:utility",
                    "work_id": "work:utility",
                    "chunk_id": "chunk:utility",
                    "creator_id": "creator:utility",
                    "creator_name": "Utility Creator",
                    "title": "Causal Citation Policy",
                    "source_uri": "https://example.test/utility",
                    "content": (
                        "Credited citations need current-turn retrieval and causal utility."
                    ),
                }
            ],
            "retrieval_trace": {
                "turn_id": "turn:utility",
                "current_turn_source_ids": ["source:utility"],
                "prior_turn_source_ids": ["source:prior"],
                "steps": [
                    {
                        "step_id": "step:retrieve",
                        "tool": "search",
                        "action": "retrieve",
                        "query": "credit causal utility",
                        "source_id": "source:utility",
                        "turn_scope": "current",
                    }
                ],
            },
            "baseline": {
                "claim_outcomes": [
                    {
                        "claim_id": "claim:utility",
                        "supported": True,
                        "confidence": 0.95,
                        "groundedness": 0.93,
                        "cited_source_ids": ["source:utility"],
                    }
                ]
            },
            "perturbation_trials": [
                {
                    "trial_id": "trial:remove",
                    "operator": "remove",
                    "target_source_ids": ["source:utility"],
                    "trace_divergence": 0.7,
                    "claim_outcomes": [
                        {
                            "claim_id": "claim:utility",
                            "supported": False,
                            "confidence": 0.18,
                            "groundedness": 0.12,
                            "cited_source_ids": [],
                        }
                    ],
                },
                {
                    "trial_id": "trial:duplicate",
                    "operator": "duplicate",
                    "target_source_ids": ["source:utility"],
                    "trace_divergence": 0.02,
                    "duplicate_credit_total": 1.0,
                    "claim_outcomes": [
                        {
                            "claim_id": "claim:utility",
                            "supported": True,
                            "confidence": 0.95,
                            "groundedness": 0.93,
                            "cited_source_ids": ["source:utility"],
                        }
                    ],
                },
            ],
        }
        report = make_evidence_utility_attribution_report(
            utility_input,
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(
            verify_evidence_utility_attribution_report(
                report,
                utility_input,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(report["summary"]["target_certification_level"], "RDLLM-L88")
        self.assertEqual(report["summary"]["status"], "ready")
        self.assertEqual(report["summary"]["causally_grounded_claim_count"], 1)
        self.assertEqual(report["summary"]["accepted_source_count"], 1)
        self.assertTrue(report["checks"]["no_prior_context_citation_drift"])
        self.assertTrue(report["checks"]["duplicate_trials_do_not_inflate_credit"])

        drifted = deepcopy(utility_input)
        drifted["retrieval_trace"]["current_turn_source_ids"] = []
        drifted["retrieval_trace"]["steps"][0]["turn_scope"] = "prior"
        drifted_report = make_evidence_utility_attribution_report(
            drifted,
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(drifted_report["summary"]["status"], "failed")
        self.assertEqual(drifted_report["summary"]["context_drift_rejection_count"], 1)

        duplicate_inflated = deepcopy(utility_input)
        duplicate_inflated["perturbation_trials"][1]["duplicate_credit_total"] = 1.1
        duplicate_report = make_evidence_utility_attribution_report(
            duplicate_inflated,
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(duplicate_report["summary"]["status"], "failed")
        self.assertEqual(
            duplicate_report["summary"]["duplicate_overcredit_rejection_count"], 1
        )

        spurious = deepcopy(utility_input)
        spurious["candidate_sources"].append(
            {
                "source_id": "source:spurious",
                "work_id": "work:spurious",
                "chunk_id": "chunk:spurious",
                "creator_id": "creator:spurious",
                "creator_name": "Spurious Creator",
                "title": "Spurious Citation",
                "source_uri": "https://example.test/spurious",
                "content": "This source is topical but does not affect the answer.",
            }
        )
        spurious["retrieval_trace"]["current_turn_source_ids"].append(
            "source:spurious"
        )
        spurious["baseline"]["claim_outcomes"][0]["cited_source_ids"].append(
            "source:spurious"
        )
        spurious["perturbation_trials"].extend(
            [
                {
                    "trial_id": "trial:remove-spurious",
                    "operator": "remove",
                    "target_source_ids": ["source:spurious"],
                    "trace_divergence": 0.01,
                    "claim_outcomes": [
                        {
                            "claim_id": "claim:utility",
                            "supported": True,
                            "confidence": 0.95,
                            "groundedness": 0.93,
                            "cited_source_ids": ["source:utility"],
                        }
                    ],
                },
                {
                    "trial_id": "trial:duplicate-spurious",
                    "operator": "duplicate",
                    "target_source_ids": ["source:spurious"],
                    "trace_divergence": 0.01,
                    "duplicate_credit_total": 1.0,
                    "claim_outcomes": [
                        {
                            "claim_id": "claim:utility",
                            "supported": True,
                            "confidence": 0.95,
                            "groundedness": 0.93,
                            "cited_source_ids": ["source:utility"],
                        }
                    ],
                },
            ]
        )
        spurious_report = make_evidence_utility_attribution_report(
            spurious,
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(spurious_report["summary"]["status"], "failed")
        self.assertEqual(spurious_report["summary"]["spurious_source_rejection_count"], 1)
        self.assertNotIn("Credited citations need current-turn retrieval", canonical_json(report))
        self.assertNotIn("What citations should receive credit?", canonical_json(report))

