    def test_style_influence_attribution_requires_license_and_copy_guard(
        self,
    ) -> None:
        style_input = {
            "event": {
                "event_id": "event:style",
                "prompt_text": "Write in Maya's registered style.",
                "output_text": (
                    "We trace the model room with bright careful rhythm; every "
                    "hidden doorway gets named, every owed thread becomes a receipt."
                ),
                "declared_style_creator_ids": ["creator:maya"],
            },
            "style_profiles": [
                {
                    "profile_id": "profile:maya",
                    "work_id": "work:maya-style",
                    "creator_id": "creator:maya",
                    "title": "Maya Style",
                    "source_uri": "registered://styles/maya",
                    "modality": "text",
                    "source_role": "style_candidate",
                    "license_status": "active",
                    "allowed_uses": ["style_generation"],
                    "style_examples": [
                        (
                            "We move through the archive with bright careful rhythm; "
                            "every fragment stays visible, every debt becomes a receipt."
                        ),
                        (
                            "The work turns quiet evidence into a living ledger; "
                            "every source remains visible and every payment finds its person."
                        ),
                    ],
                },
                {
                    "profile_id": "profile:decoy",
                    "work_id": "work:decoy",
                    "creator_id": "creator:decoy",
                    "title": "Decoy Style",
                    "source_uri": "registered://styles/decoy",
                    "modality": "text",
                    "source_role": "anti_style",
                    "license_status": "active",
                    "allowed_uses": ["style_generation"],
                    "style_examples": [
                        "Short blunt notes. Minimal cadence. Plain hard commands. No ornate rhythm."
                    ],
                },
            ],
        }
        report = make_style_influence_attribution_report(
            style_input,
            gross_revenue=Decimal("2.00"),
            signing_secret="secret",
        )
        self.assertEqual(
            verify_style_influence_attribution_report(
                report,
                style_input,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(report["summary"]["status"], "ready")
        self.assertEqual(report["summary"]["target_certification_level"], "RDLLM-L90")
        self.assertEqual(report["summary"]["accepted_style_count"], 1)
        self.assertEqual(report["summary"]["anti_style_rejection_count"], 1)
        self.assertTrue(report["checks"]["copy_overlap_routes_away_from_style_payout"])
        self.assertTrue(report["checks"]["public_report_does_not_embed_private_style_text"])
        self.assertNotIn("We move through the archive", canonical_json(report))

        copy_input = deepcopy(style_input)
        copy_input["event"]["output_text"] = (
            "We move through the archive with bright careful rhythm; every fragment "
            "stays visible, every debt becomes a receipt."
        )
        copy_report = make_style_influence_attribution_report(
            copy_input,
            gross_revenue=Decimal("2.00"),
            signing_secret="secret",
        )
        self.assertEqual(copy_report["summary"]["accepted_style_count"], 0)
        self.assertGreaterEqual(copy_report["summary"]["copy_overlap_rejection_count"], 1)

        unlicensed = deepcopy(style_input)
        unlicensed["style_profiles"][0]["license_status"] = "revoked"
        unlicensed_report = make_style_influence_attribution_report(
            unlicensed,
            gross_revenue=Decimal("2.00"),
            signing_secret="secret",
        )
        self.assertEqual(unlicensed_report["summary"]["accepted_style_count"], 0)
        self.assertGreaterEqual(unlicensed_report["summary"]["license_block_count"], 1)

