        post_hoc_receipt = make_citation_reliance_receipt(
            post_hoc,
            issued_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(post_hoc_receipt["summary"]["status"], "needs_review")
        self.assertFalse(
            post_hoc_receipt["checks"]["every_visible_source_has_satisfied_lock"]
        )

        no_utility = deepcopy(reliance_input)
