        no_utility_receipt = make_citation_reliance_receipt(
            no_utility,
            issued_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(no_utility_receipt["summary"]["status"], "needs_review")
        self.assertFalse(
            no_utility_receipt["checks"]["every_visible_source_has_causal_utility"]
        )

        hidden_paid = deepcopy(reliance_input)
        hidden_paid["source_access_lease_report"]["source_usage_rows"].append(
            {
                "source_usage_id": "use:S2:hidden",
                "source_label": "S2",
                "work_id": "work:2",
                "chunk_id": "chunk:2",
                "source_uri": "https://publisher.example/hidden",
                "content_hash": stable_hash("hidden"),
                "usage_purpose": "retrieval_inference",
                "settlement_status": "direct",
                "escrow_account": "",
            }
        )
        hidden_paid_receipt = make_citation_reliance_receipt(
            hidden_paid,
            issued_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(hidden_paid_receipt["summary"]["status"], "needs_review")
        self.assertFalse(
            hidden_paid_receipt["checks"]["no_paid_source_without_visible_footer"]
        )

        tampered = deepcopy(receipt)
        tampered["source_reliance_rows"][0]["causal_utility_count"] = 0
        self.assertTrue(
            verify_citation_reliance_receipt(
                tampered,
                reliance_input,
                signing_secret="secret",
            )
        )

