        self.assertEqual(receipt["summary"]["target_certification_level"], "RDLLM-L102")
        self.assertEqual(receipt["summary"]["status"], "ready")
        self.assertEqual(receipt["summary"]["visible_source_count"], 1)
        self.assertEqual(receipt["summary"]["public_region_bound_claim_count"], 1)
