        self.assertTrue(receipt["checks"]["source_availability_inspectable"])
        self.assertTrue(receipt["checks"]["claim_regions_publicly_bound"])
        self.assertTrue(receipt["checks"]["citation_reliance_covers_visible_sources"])
        self.assertTrue(receipt["checks"]["license_transactions_cover_visible_sources"])
        self.assertTrue(receipt["checks"]["footer_rows_explain_source_selection"])
