    def test_source_footer_delivery_binds_grounded_footer_to_gateway_egress(self) -> None:
        def load_artifact(name: str):
            return json.loads((ROOT / "artifacts" / name).read_text(encoding="utf-8"))

        receipt_input = load_artifact("source_footer_delivery_input.json")
        receipt = make_source_footer_delivery_receipt(
            receipt_input,
            issuer="rdllm-local-demo",
            issued_at="2026-05-31T00:00:00Z",
            signing_secret="secret",
        )

        self.assertEqual(
            verify_source_footer_delivery_receipt(
                receipt,
                receipt_input,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(receipt["summary"]["status"], "ready")
        self.assertEqual(receipt["summary"]["target_certification_level"], "RDLLM-L103")
        self.assertTrue(receipt["checks"]["all_grounded_sources_visible_in_rendered_output"])
        self.assertTrue(receipt["checks"]["all_grounded_sources_visible_in_delivered_output"])
        self.assertTrue(receipt["checks"]["all_grounded_claim_spans_visible"])
        self.assertTrue(receipt["checks"]["delivered_output_matches_gateway"])
        self.assertTrue(receipt["checks"]["delivery_metadata_contains_verifier_handles"])
        self.assertTrue(receipt["checks"]["delivery_rows_carry_source_rationale"])
        self.assertTrue(receipt["summary"]["source_selection_rationale_delivered"])
        self.assertEqual(
            receipt["source_delivery_rows"][0]["source_rationale_hash"],
            receipt["source_delivery_rows"][0]["source_rationale"][
                "source_rationale_hash"
            ],
        )

        missing_source = deepcopy(receipt_input)
        copied_output = missing_source["proof_carrying_response"]["display"][
            "copied_output"
        ]
        for row in missing_source["grounded_source_footer"]["footer_rows"]:
            copied_output = copied_output.replace(
                f"[{row['label']}]",
                f"[X{row['label']}]",
            )
        missing_source["delivered_output"] = copied_output
        missing_receipt = make_source_footer_delivery_receipt(
            missing_source,
            issuer="rdllm-local-demo",
            issued_at="2026-05-31T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(missing_receipt["summary"]["status"], "needs_review")
        self.assertFalse(
            missing_receipt["checks"][
                "all_grounded_sources_visible_in_delivered_output"
            ]
        )
        self.assertFalse(missing_receipt["checks"]["delivered_output_matches_gateway"])

        missing_handles = deepcopy(receipt_input)
        missing_handles["grounded_source_footer"]["proof_rows"][0][
            "proof_row_hash"
        ] = ""
        missing_handles["grounded_source_footer"][
            "grounded_source_footer_hash"
        ] = hash_payload(
            {
                key: value
                for key, value in missing_handles["grounded_source_footer"].items()
                if key not in {"grounded_source_footer_hash", "signature"}
            }
        )
        missing_handles_receipt = make_source_footer_delivery_receipt(
            missing_handles,
            issuer="rdllm-local-demo",
            issued_at="2026-05-31T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(missing_handles_receipt["summary"]["status"], "needs_review")
        self.assertFalse(
            missing_handles_receipt["checks"][
                "delivery_metadata_contains_verifier_handles"
            ]
        )

        receipt_text = canonical_json(receipt)
        for private_text in receipt_input["private_strings"]:
            self.assertNotIn(private_text, receipt_text)

        tampered = deepcopy(receipt)
        tampered["source_delivery_rows"][0][
            "label_visible_in_delivered_output"
        ] = False
        self.assertTrue(
            verify_source_footer_delivery_receipt(
                tampered,
                receipt_input,
                signing_secret="secret",
            )
        )

