    def test_source_origin_lineage_blocks_synthetic_source_laundering(self) -> None:
        def load_artifact(name: str):
            return json.loads((ROOT / "artifacts" / name).read_text(encoding="utf-8"))

        warranted_footer = load_artifact("warranted_source_footer.json")
        source_rows = warranted_footer["source_rows"]
        lineage_input = {
            "warranted_source_footer": warranted_footer,
            "grounded_source_footer": load_artifact("grounded_source_footer.json"),
            "source_authenticity_report": load_artifact("source_authenticity_report.json"),
            "creator_license_contract": load_artifact("creator_license_contract.json"),
            "origin_attestations": [
                {
                    "label": row["label"],
                    "work_id": row["work_id"],
                    "chunk_id": row["chunk_id"],
                    "origin_class": "human_original",
                    "origin_attestation_hash": stable_hash(
                        f"origin-attestation:{row['work_id']}:{row['chunk_id']}"
                    ),
                    "origin_attestation_issuer": "registry:rdllm-origin",
                    "attestation_signature_verified": True,
                    "attestation_issuer_trusted": True,
                    "synthetic_generation_disclosed": False,
                    "upstream_sources": [],
                }
                for row in source_rows
            ],
            "private_strings": [
                "private source-origin lineage prompt",
                "private synthetic source replay text",
            ],
        }
        lineage_input["origin_attestations"][1].update(
            {
                "origin_class": "synthetic_with_lineage",
                "synthetic_generation_disclosed": True,
                "upstream_sources": [
                    {
                        "upstream_creator_id": "creator:human-a",
                        "upstream_work_id": "work:human-a",
                        "upstream_content_hash": stable_hash("human-a-source"),
                        "license_status": "active",
                        "upstream_share": 0.7,
                        "upstream_lineage_hash": stable_hash("lineage-a"),
                    },
                    {
                        "upstream_creator_id": "creator:human-b",
                        "upstream_work_id": "work:human-b",
                        "upstream_content_hash": stable_hash("human-b-source"),
                        "license_status": "active",
                        "upstream_share": 0.3,
                        "upstream_lineage_hash": stable_hash("lineage-b"),
                    },
                ],
            }
        )
        report = make_source_origin_lineage_report(
            lineage_input,
            issuer="rdllm-local-demo",
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(
            verify_source_origin_lineage_report(
                report,
                lineage_input=lineage_input,
                signing_secret="secret",
            ),
            [],
        )
        synthetic_row = next(
            row
            for row in report["source_origin_rows"]
            if row["origin_class"] == "synthetic_with_lineage"
        )
        self.assertEqual(synthetic_row["settlement_action"], "split_payout_to_upstream_creators")
        self.assertEqual(synthetic_row["upstream_creator_count"], 2)
        self.assertEqual(synthetic_row["direct_source_creator_share"], 0.0)
        self.assertFalse(synthetic_row["direct_payout_allowed"])
        self.assertTrue(synthetic_row["lineage_settlement_allowed"])
        self.assertEqual(report["summary"]["upstream_royalty_row_count"], 2)
        self.assertNotIn("private synthetic source replay text", canonical_json(report))

        missing_lineage = deepcopy(lineage_input)
        missing_lineage["origin_attestations"][1]["upstream_sources"] = []
        escrow_report = make_source_origin_lineage_report(
            missing_lineage,
            issuer="rdllm-local-demo",
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        escrow_row = next(
            row
            for row in escrow_report["source_origin_rows"]
            if row["origin_class"] == "synthetic_with_lineage"
        )
        self.assertEqual(escrow_row["settlement_action"], "origin_review_escrow")
        self.assertEqual(escrow_row["origin_review_escrow_share"], 1.0)
        self.assertTrue(
            escrow_report["checks"]["synthetic_sources_have_upstream_lineage_or_escrow"]
        )

        unknown_origin = deepcopy(lineage_input)
        unknown_origin["origin_attestations"][0]["origin_class"] = "unknown"
        unknown_report = make_source_origin_lineage_report(
            unknown_origin,
            issuer="rdllm-local-demo",
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        unknown_row = next(
            row for row in unknown_report["source_origin_rows"] if row["origin_class"] == "unknown"
        )
        self.assertEqual(unknown_row["settlement_action"], "origin_review_escrow")
        self.assertTrue(unknown_report["checks"]["unknown_or_unattributed_sources_escrowed"])

        leaky = deepcopy(report)
        leaky["source_text"] = "private synthetic source replay text"
        self.assertTrue(
            any(
                "private field" in error
                for error in verify_source_origin_lineage_report(
                    leaky,
                    lineage_input=lineage_input,
                    signing_secret="secret",
                )
            )
        )

