    def test_foundation_runtime_router_controls_multi_provider_fallbacks(self) -> None:
        def load_artifact(name: str):
            return json.loads((ROOT / "artifacts" / name).read_text(encoding="utf-8"))

        runtime_adapter = load_artifact("foundation_runtime_adapter.json")
        provider_conformance = load_artifact("foundation_provider_conformance.json")
        composite_adapter = load_artifact("composite_foundation_adapter.json")
        foundation_profile = load_artifact("foundation_api_profile.json")
        discovery_manifest = load_artifact("discovery_manifest.json")
        conformance_by_family = {
            row["provider_family"]: row
            for row in provider_conformance["provider_conformance_rows"]
        }
        selected_family = runtime_adapter["summary"]["provider_family"]
        selected_route_id = f"route:{selected_family}"
        candidate_routes = []
        for row in composite_adapter["provider_adapter_rows"]:
            family = row["provider_family"]
            selected = family == selected_family
            candidate_routes.append(
                {
                    "route_id": f"route:{family}",
                    "route_role": "selected" if selected else "fallback",
                    "provider_id": row["provider_id"],
                    "provider_family": family,
                    "native_api_version": row["native_api_version"],
                    "native_model": row["native_model"],
                    "provider_adapter_row_hash": row["provider_adapter_row_hash"],
                    "foundation_provider_conformance_row_hash": conformance_by_family[
                        family
                    ]["foundation_provider_conformance_row_hash"],
                    "runtime_adapter_hash": (
                        runtime_adapter["foundation_runtime_adapter_hash"]
                        if selected
                        else stable_hash(f"{family}:fallback-runtime-adapter")
                    ),
                    "minimum_attribution_level": "RDLLM-L127",
                    "fallback_decision": "release" if selected else "block_display",
                    "runtime_release_authorized": selected,
                    "fail_closed_on_error": True,
                    "selection_score_hash": stable_hash(f"{family}:selection-score"),
                    "health_check_hash": stable_hash(f"{family}:health-check"),
                    "route_decision_hash": stable_hash(f"{family}:route-decision"),
                    "observed_failure_modes": [] if selected else ["not_selected"],
                }
            )
        router_input = {
            "foundation_runtime_adapter": runtime_adapter,
            "foundation_provider_conformance": provider_conformance,
            "composite_foundation_adapter": composite_adapter,
            "foundation_api_profile": foundation_profile,
            "discovery_manifest": discovery_manifest,
            "selected_route_id": selected_route_id,
            "candidate_routes": candidate_routes,
            "router_observation_hash": stable_hash("test router observation"),
            "private_strings": ["private router prompt", "private router source text"],
        }
        report = make_foundation_runtime_router_report(
            router_input,
            issuer="rdllm-local-demo",
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(
            verify_foundation_runtime_router_report(
                report,
                router_input=router_input,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(report["summary"]["status"], "released")
        self.assertEqual(report["summary"]["target_certification_level"], "RDLLM-L128")
        self.assertEqual(report["summary"]["covered_provider_family_count"], 10)
        self.assertTrue(report["checks"]["fallback_paths_fail_closed"])
        self.assertTrue(report["checks"]["selected_route_matches_runtime_adapter"])

