    def test_universal_composition_receipt_binds_multi_provider_segments(self) -> None:
        def load_artifact(name: str):
            return json.loads((ROOT / "artifacts" / name).read_text(encoding="utf-8"))

        def hashed(field: str, payload: dict) -> dict:
            item = deepcopy(payload)
            item[field] = hash_payload(item)
            return item

        def make_segment_attestation(
            *,
            provider_id: str,
            provider_family: str,
            native_api_version: str,
            native_model: str,
            native_response_id: str,
            native_output_hash: str,
            response_envelope_hash: str,
        ) -> dict:
            runtime_adapter = hashed(
                "foundation_runtime_adapter_hash",
                {
                    "runtime_adapter_version": "rdllm-foundation-runtime-adapter/v1",
                    "summary": {
                        "status": "released",
                        "target_certification_level": "RDLLM-L127",
                        "provider_id": provider_id,
                        "provider_family": provider_family,
                        "runtime_release_authorized": True,
                    },
                    "runtime_decision": {"release_authorized": True},
                    "native_response_observation": {
                        "provider_id": provider_id,
                        "provider_family": provider_family,
                        "native_api_version": native_api_version,
                        "native_response_id": native_response_id,
                        "native_model": native_model,
                        "native_status": "completed",
                        "native_output_hash": native_output_hash,
                    },
                    "normalized_rdllm_contract": {
                        "response_envelope_hash": response_envelope_hash,
                        "native_output_hash": native_output_hash,
                    },
                },
            )
            route_id = f"route:{provider_family}"
            route_decision_hash = stable_hash(f"test l130 route:{provider_family}")
            runtime_router = hashed(
                "foundation_runtime_router_hash",
                {
                    "runtime_router_version": "rdllm-foundation-runtime-router/v1",
                    "summary": {
                        "status": "released",
                        "target_certification_level": "RDLLM-L128",
                        "router_release_authorized": True,
                        "selected_provider_family": provider_family,
                    },
                    "router_decision": {
                        "release_authorized": True,
                        "selected_route_id": route_id,
                    },
                    "selected_route_binding": {
                        "route_id": route_id,
                        "provider_id": provider_id,
                        "provider_family": provider_family,
                        "native_api_version": native_api_version,
                        "native_model": native_model,
                        "foundation_runtime_adapter_hash": runtime_adapter[
                            "foundation_runtime_adapter_hash"
                        ],
                        "route_decision_hash": route_decision_hash,
                    },
                },
            )
            response_binding = {
                "native_response_id": native_response_id,
                "native_output_hash": native_output_hash,
                "response_envelope_hash": response_envelope_hash,
            }
            request_response_binding = {
                **response_binding,
                "request_projection_hash": stable_hash(
                    f"test l130 request:{provider_family}"
                ),
                "response_binding_hash": hash_payload(response_binding),
                "api_boundary_attestation_hash": stable_hash(
                    f"test l130 api boundary:{provider_family}"
                ),
            }
            deployment_secret = f"test-l130-deployment-secret:{provider_family}"
            deployment_key_id = f"deployment-key:test-l130:{provider_family}"
            statement = make_model_deployment_statement(
                provider_id=provider_id,
                provider_family=provider_family,
                deployment_id=f"deployment:test-l130:{provider_family}",
                native_model=native_model,
                model_version="2026-06-02",
                model_manifest_hash=stable_hash(
                    f"test l130 model manifest:{provider_family}"
                ),
                weights_commitment_hash=stable_hash(
                    f"test l130 weights:{provider_family}"
                ),
                tokenizer_hash=stable_hash(f"test l130 tokenizer:{provider_family}"),
                inference_stack_hash=stable_hash(
                    f"test l130 inference:{provider_family}"
                ),
                safety_policy_hash=stable_hash(f"test l130 safety:{provider_family}"),
                attribution_policy_hash=stable_hash(
                    f"test l130 attribution:{provider_family}"
                ),
                selected_route_id=route_id,
                route_decision_hash=route_decision_hash,
                foundation_runtime_router_hash=runtime_router[
                    "foundation_runtime_router_hash"
                ],
                foundation_runtime_adapter_hash=runtime_adapter[
                    "foundation_runtime_adapter_hash"
                ],
                request_projection_hash=request_response_binding[
                    "request_projection_hash"
                ],
                response_binding_hash=request_response_binding["response_binding_hash"],
                api_boundary_attestation_hash=request_response_binding[
                    "api_boundary_attestation_hash"
                ],
                deployment_key_id=deployment_key_id,
                deployment_secret=deployment_secret,
                created_at="2026-06-01T00:00:00Z",
                valid_from="2026-01-01T00:00:00Z",
                valid_until="2026-12-31T23:59:59Z",
            )
            return make_foundation_model_deployment_attestation_report(
                {
                    "foundation_runtime_router": runtime_router,
                    "foundation_runtime_adapter": runtime_adapter,
                    "trusted_deployment_keys": [
                        {
                            "provider_id": provider_id,
                            "provider_family": provider_family,
                            "deployment_key_id": deployment_key_id,
                            "deployment_key_hash": make_deployment_key_hash(
                                provider_id,
                                deployment_key_id,
                                deployment_secret,
                            ),
                            "status": "active",
                            "valid_from": "2026-01-01T00:00:00Z",
                            "valid_until": "2026-12-31T23:59:59Z",
                            "verification_secret": deployment_secret,
                        }
                    ],
                    "model_deployment_statement": statement,
                    "request_response_binding": request_response_binding,
                    "private_strings": ["private test l130 segment request"],
                },
                issuer="rdllm-local-demo",
                created_at="2026-06-01T00:00:00Z",
                signing_secret="secret",
            )

        response_envelope = load_artifact("response_envelope.json")
        source_footer_delivery = load_artifact("source_footer_delivery.json")
        composite_adapter = load_artifact("composite_foundation_adapter.json")
        provider_conformance = load_artifact("foundation_provider_conformance.json")
        openai_attestation = load_artifact("foundation_model_deployment_attestation.json")
        anthropic_attestation = make_segment_attestation(
            provider_id="provider:anthropic-messages",
            provider_family="anthropic_messages",
            native_api_version="messages/v1",
            native_model="anthropic:messages-compatible:test-l130",
            native_response_id="msg_test_l130_anthropic",
            native_output_hash=stable_hash("test l130 anthropic segment"),
            response_envelope_hash=response_envelope["envelope_hash"],
        )
        attestations = [openai_attestation, anthropic_attestation]

        segments = []
        telemetry_spans = []
        for index, attestation in enumerate(attestations, start=1):
            summary = attestation["summary"]
            request_response = attestation["request_response_binding"]
            segment_id = f"segment:{summary['provider_family']}"
            segments.append(
                {
                    "segment_id": segment_id,
                    "segment_role": "synthesis_part",
                    "provider_id": summary["provider_id"],
                    "provider_family": summary["provider_family"],
                    "native_model": summary["native_model"],
                    "deployment_id": summary["deployment_id"],
                    "native_response_id": request_response["native_response_id"],
                    "native_output_hash": request_response["native_output_hash"],
                    "response_envelope_hash": request_response[
                        "response_envelope_hash"
                    ],
                    "source_footer_delivery_hash": source_footer_delivery[
                        "source_footer_delivery_hash"
                    ],
                    "deployment_attestation_hash": attestation[
                        "foundation_model_deployment_attestation_hash"
                    ],
                    "merge_input_hash": stable_hash(f"test l130 merge input:{index}"),
                    "merge_output_span_hash": stable_hash(
                        f"test l130 merge span:{index}"
                    ),
                    "provider_weight": "0.650000" if index == 1 else "0.350000",
                    "claim_ids": [f"claim:test-l130:{index}"],
                    "source_labels": [f"S{index}"],
                }
            )
            telemetry_spans.append(
                {
                    "segment_id": segment_id,
                    "provider_id": summary["provider_id"],
                    "provider_family": summary["provider_family"],
                    "native_response_id": request_response["native_response_id"],
                    "response_envelope_hash": request_response[
                        "response_envelope_hash"
                    ],
                    "trace_id_hash": stable_hash(f"test l130 trace:{index}"),
                    "span_id_hash": stable_hash(f"test l130 span:{index}"),
                    "span_kind": "CLIENT",
                    "gen_ai_operation": "chat",
                }
            )

        composition_input = {
            "response_envelope": response_envelope,
            "source_footer_delivery": source_footer_delivery,
            "composite_foundation_adapter": composite_adapter,
            "foundation_provider_conformance": provider_conformance,
            "deployment_attestations": attestations,
            "composition_plan": {
                "composition_id": "composition:test-l130:universal",
                "composition_mode": "provider_segment_merge",
                "merge_policy": "hash_bound_segment_merge",
                "final_response_envelope_hash": response_envelope["envelope_hash"],
                "final_rendered_output_hash": response_envelope["response"][
                    "rendered_output_hash"
                ],
                "source_footer_delivery_hash": source_footer_delivery[
                    "source_footer_delivery_hash"
                ],
            },
            "segments": segments,
            "telemetry_span_bindings": telemetry_spans,
            "private_strings": [
                "private test l130 segment request",
                "private test l130 composite answer",
            ],
        }
        report = make_universal_composition_receipt(
            composition_input,
            issuer="rdllm-local-demo",
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(
            verify_universal_composition_receipt(
                report,
                composition_input=composition_input,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(report["summary"]["status"], "released")
        self.assertEqual(report["summary"]["target_certification_level"], "RDLLM-L130")
        self.assertEqual(report["summary"]["provider_segment_count"], 2)
        self.assertTrue(
            report["checks"]["each_segment_has_single_matching_deployment_attestation"]
        )
        self.assertTrue(report["checks"]["provider_weights_conserve_unit"])

        missing_attestation = deepcopy(composition_input)
        missing_attestation["deployment_attestations"] = missing_attestation[
            "deployment_attestations"
        ][:-1]
        missing_report = make_universal_composition_receipt(
            missing_attestation,
            issuer="rdllm-local-demo",
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(missing_report["summary"]["status"], "blocked")
        self.assertIn(
            "segment_deployment_attestation_mismatch",
            missing_report["composition_decision"]["failure_modes"],
        )

        bad_weight = deepcopy(composition_input)
        bad_weight["segments"][0]["provider_weight"] = "0.500000"
        bad_weight_report = make_universal_composition_receipt(
            bad_weight,
            issuer="rdllm-local-demo",
            created_at="2026-06-01T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(bad_weight_report["summary"]["status"], "blocked")
        self.assertIn(
            "provider_weight_conservation_failure",
            bad_weight_report["composition_decision"]["failure_modes"],
        )

        leaky = deepcopy(report)
        leaky["raw_composition_payload"] = "private test l130 composite answer"
        self.assertTrue(
            any(
                "private field" in error
                for error in verify_universal_composition_receipt(
                    leaky,
                    composition_input=composition_input,
                    signing_secret="secret",
                )
            )
        )

