        def load_artifact(name: str) -> dict[str, Any]:
            return json.loads((ROOT / "artifacts" / name).read_text(encoding="utf-8"))

        def rehash(field: str, artifact: dict[str, Any]) -> dict[str, Any]:
            updated = deepcopy(artifact)
