    def test_universal_foundation_provider_binding_matrix_maps_native_routes(
        self,
    ) -> None:
        composite_contract = json.loads(
            (
                ROOT
                / "artifacts"
                / "universal_composite_rdllm_contract.json"
            ).read_text(encoding="utf-8")
        )

        def domain_row(provider: str, domain: str) -> dict[str, Any]:
            return {
                "domain_hash": stable_hash(f"test-l168:domain:{provider}:{domain}"),
                "fixture_hash": stable_hash(f"test-l168:fixture:{provider}:{domain}"),
                "verifier_hash": stable_hash(f"test-l168:verifier:{provider}:{domain}"),
                "drift_hash": stable_hash(f"test-l168:drift:{provider}:{domain}"),
                "mapped": True,
                "tested": True,
                "l167_bound": True,
                "fail_closed": True,
            }

        def provider_row(provider: str) -> dict[str, Any]:
            return {
                "provider_binding_hash": stable_hash(f"test-l168:provider:{provider}"),
                "native_api_contract_hash": stable_hash(
                    f"test-l168:native-api:{provider}"
                ),
                "adapter_hash": stable_hash(f"test-l168:adapter:{provider}"),
                "conformance_fixture_hash": stable_hash(
                    f"test-l168:conformance:{provider}"
                ),
                "drift_canary_hash": stable_hash(f"test-l168:canary:{provider}"),
                "telemetry_mapping_hash": stable_hash(
                    f"test-l168:telemetry:{provider}"
                ),
                "settlement_meter_hash": stable_hash(
                    f"test-l168:settlement:{provider}"
                ),
                "revocation_status_hash": stable_hash(
                    f"test-l168:revocation:{provider}"
                ),
                "public_verifier_hash": stable_hash(
                    f"test-l168:public-verifier:{provider}"
                ),
                "capabilities": {
                    capability: True
                    for capability in L168_REQUIRED_NATIVE_CAPABILITIES
                },
                "domain_bindings": {
                    domain: domain_row(provider, domain)
                    for domain in L168_REQUIRED_BINDING_DOMAINS
                },
                "provider_family_supported": True,
                "native_api_bound_to_l167": True,
                "all_required_capabilities_supported": True,
                "domain_bindings_complete": True,
                "fail_closed": True,
                "private_payloads_excluded": True,
            }

        matrix_input = {
            "universal_composite_rdllm_contract": composite_contract,
            "provider_binding_rows": {
                provider: provider_row(provider)
                for provider in L168_REQUIRED_PROVIDER_FAMILIES
            },
            "negative_provider_binding_rows": {
                failure: {
                    "fixture_hash": stable_hash(f"test-l168:negative:{failure}"),
                    "expected_reject": True,
                    "observed_reject": True,
                    "provider_claim_blocked": True,
                    "invocation_blocked": True,
                    "response_release_blocked": True,
                    "source_footer_reliance_blocked": True,
                    "settlement_held": True,
                    "public_status_marked_failed": True,
                }
                for failure in L168_REQUIRED_NEGATIVE_PROVIDER_FAILURES
            },
            "private_strings": ["private test l168 provider binding fixture"],
        }

        matrix = make_universal_foundation_provider_binding_matrix(
            matrix_input,
            issuer="rdllm-local-demo",
            created_at="2026-06-03T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(
            verify_universal_foundation_provider_binding_matrix(
                matrix_input,
                matrix,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(matrix["summary"]["status"], "ready")
        self.assertEqual(
            matrix["summary"]["target_certification_level"], "RDLLM-L168"
        )
        self.assertEqual(
            matrix["summary"]["ready_provider_family_count"],
            len(L168_REQUIRED_PROVIDER_FAMILIES),
        )
        self.assertTrue(
            matrix["provider_binding_decision"][
                "universal_provider_adoption_claim_allowed"
            ]
        )
        self.assertTrue(
            matrix["provider_binding_decision"]["bound_provider_invocation_allowed"]
        )

        blocked_contract = deepcopy(matrix_input)
        blocked_contract["universal_composite_rdllm_contract"][
            "contract_decision"
        ]["universal_rdllm_claim_allowed"] = False
        blocked_matrix = make_universal_foundation_provider_binding_matrix(
            blocked_contract,
            issuer="rdllm-local-demo",
            created_at="2026-06-03T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(blocked_matrix["summary"]["status"], "blocked")
        self.assertIn(
            "composite_contract_l167_ready",
            blocked_matrix["provider_binding_decision"]["failure_modes"],
        )

        missing_provider = deepcopy(matrix_input)
        missing_provider["provider_binding_rows"].pop(L168_REQUIRED_PROVIDER_FAMILIES[0])
        blocked_provider = make_universal_foundation_provider_binding_matrix(
            missing_provider,
            issuer="rdllm-local-demo",
            created_at="2026-06-03T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(blocked_provider["summary"]["status"], "blocked")
        self.assertIn(
            "provider_families_complete",
            blocked_provider["provider_binding_decision"]["failure_modes"],
        )

        incomplete_domain = deepcopy(matrix_input)
        incomplete_domain["provider_binding_rows"][L168_REQUIRED_PROVIDER_FAMILIES[1]][
            "domain_bindings"
        ][L168_REQUIRED_BINDING_DOMAINS[0]]["mapped"] = False
        blocked_domain = make_universal_foundation_provider_binding_matrix(
            incomplete_domain,
            issuer="rdllm-local-demo",
            created_at="2026-06-03T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(blocked_domain["summary"]["status"], "blocked")
        self.assertIn(
            "provider_domain_bindings_complete",
            blocked_domain["provider_binding_decision"]["failure_modes"],
        )

        missing_capability = deepcopy(matrix_input)
        missing_capability["provider_binding_rows"][L168_REQUIRED_PROVIDER_FAMILIES[2]][
            "capabilities"
        ][L168_REQUIRED_NATIVE_CAPABILITIES[0]] = False
        blocked_capability = make_universal_foundation_provider_binding_matrix(
            missing_capability,
            issuer="rdllm-local-demo",
            created_at="2026-06-03T00:00:00Z",
            signing_secret="secret",
        )
        self.assertEqual(blocked_capability["summary"]["status"], "blocked")
        self.assertIn(
            "native_capabilities_complete",
            blocked_capability["provider_binding_decision"]["failure_modes"],
        )

        leaky = deepcopy(matrix)
        leaky["raw_native_request"] = "private test l168 provider binding fixture"
        self.assertTrue(
            any(
                "private field" in error
                for error in verify_universal_foundation_provider_binding_matrix(
                    matrix_input,
                    leaky,
                    signing_secret="secret",
                )
            )
        )

