    def test_revenue_allocation_report_binds_source_pools_to_event_gross(self) -> None:
        events = [
            self.engine.generate(
                "How should subscription revenue be allocated to attributable events?",
                gross_revenue=Decimal("1.00"),
            ),
            self.engine.generate(
                "How should API meter revenue be allocated to attributable events?",
                gross_revenue=Decimal("2.00"),
            ),
        ]
        ledger = RoyaltyLedger()
        for event in events:
            ledger.record(event)
        receipts = [
            make_attribution_receipt(
                event,
                issuer="test-issuer",
                issued_at=f"2026-05-29T00:00:2{index}Z",
                signing_secret="secret",
            )
            for index, event in enumerate(events)
        ]
        revenue_sources = [
            {
                "source_id": "revenue:subscription:test",
                "source_type": "subscription_pool",
                "period_start": "2026-05-01",
                "period_end": "2026-05-31",
                "currency": "USD",
                "gross_revenue": "1.200000",
                "allocation_basis": "ledger_gross_revenue",
                "subscription_pool_hash": hash_payload("subscription-pool:test"),
            },
            {
                "source_id": "revenue:api:test",
                "source_type": "api_metering",
                "period_start": "2026-05-01",
                "period_end": "2026-05-31",
                "currency": "USD",
                "gross_revenue": "1.800000",
                "allocation_basis": "ledger_gross_revenue",
                "meter_event_root": hash_payload("api-meter-root:test"),
                "invoice_hash": hash_payload("invoice:test"),
            },
        ]
        report = make_revenue_allocation_report(
            ledger.to_dict(),
            revenue_sources=revenue_sources,
            receipts=receipts,
            allocation_policy={
                "policy_id": "test:ledger-gross",
                "allocation_mode": "ledger_gross_revenue",
                "currency": "USD",
            },
            issuer="test-issuer",
            created_at="2026-05-29T00:00:24Z",
            signing_secret="secret",
        )

        self.assertEqual(
            verify_revenue_allocation_report(
                report,
                ledger.to_dict(),
                revenue_sources=revenue_sources,
                receipts=receipts,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(
            report["report_version"],
            "rdllm-revenue-allocation-report/v1",
        )
        self.assertEqual(report["summary"]["status"], "ready")
        self.assertEqual(report["summary"]["target_certification_level"], "RDLLM-L46")
        self.assertEqual(report["summary"]["gross_revenue_total"], "3.000000")
        self.assertEqual(report["summary"]["creator_pool_total"], "1.650000")
        self.assertTrue(report["checks"]["ledger_gross_revenue_matches_allocations"])
        self.assertTrue(report["checks"]["creator_pool_conserved_from_allocated_revenue"])
        self.assertTrue(report["checks"]["receipt_hashes_bind_events"])
        report_text = canonical_json(report)
        self.assertNotIn(events[0].prompt, report_text)
        self.assertNotIn(events[1].output, report_text)
        self.assertNotIn("raw-customer-account", report_text)

        private_sources = deepcopy(revenue_sources)
        private_sources[0]["account_id"] = "raw-customer-account"
        private_report = make_revenue_allocation_report(
            ledger.to_dict(),
            revenue_sources=private_sources,
            receipts=receipts,
            allocation_policy=report["allocation_policy"],
            issuer="test-issuer",
            created_at="2026-05-29T00:00:24Z",
            signing_secret="secret",
        )
        self.assertEqual(private_report["summary"]["status"], "failed")
        self.assertFalse(
            private_report["checks"]["private_billing_fields_absent_from_input"]
        )

        tampered = deepcopy(report)
        tampered["event_allocation_rows"][0]["allocated_gross_revenue"] = "0.000000"
        errors = verify_revenue_allocation_report(
            tampered,
            ledger.to_dict(),
            revenue_sources=revenue_sources,
            receipts=receipts,
            signing_secret="secret",
        )
        self.assertTrue(
            any("hash" in error or "recomputed inputs" in error for error in errors)
        )

