    def test_proof_dependency_graph_publishes_acyclic_replay_order(self) -> None:
        def hashed(field: str, payload: dict[str, object]) -> dict[str, object]:
            artifact = dict(payload)
            artifact[field] = hash_payload(artifact)
            return artifact

        artifacts = [
            (
                "certification_report",
                "certification_report",
                hashed("report_hash", {"summary": {"highest_level": "RDLLM-L48"}}),
            ),
            (
                "provider_card",
                "provider_attribution_card",
                hashed("card_hash", {"provider": {"id": "provider:test"}, "private_note": "hide-me"}),
            ),
            (
                "source_verification",
                "source_verification_report",
                hashed("report_hash", {"summary": {"status": "verified"}}),
            ),
            (
                "source_confidence",
                "source_confidence_report",
                hashed("report_hash", {"summary": {"status": "verified"}}),
            ),
            (
                "revenue_allocation",
                "revenue_allocation_report",
                hashed("report_hash", {"summary": {"status": "ready"}}),
            ),
            (
                "finance_ledger",
                "finance_ledger_attestation",
                hashed("attestation_hash", {"summary": {"status": "ready"}}),
            ),
        ]
        dependencies = [
            {
                "dependent": "provider_card",
                "dependency": "certification_report",
                "edge_class": "replay_dependency",
                "reason": "provider_card_binds_certification",
            },
            {
                "dependent": "source_confidence",
                "dependency": "source_verification",
                "edge_class": "replay_dependency",
                "reason": "confidence_uses_materialized_sources",
            },
            {
                "dependent": "finance_ledger",
                "dependency": "revenue_allocation",
                "edge_class": "replay_dependency",
                "reason": "finance_reconciles_allocation",
            },
        ]
        graph = make_proof_dependency_graph(
            artifacts,
            dependencies=dependencies,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:26Z",
            signing_secret="secret",
        )

        self.assertEqual(
            verify_proof_dependency_graph(
                graph,
                artifacts,
                dependencies=dependencies,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(graph["graph_version"], "rdllm-proof-dependency-graph/v1")
        self.assertEqual(graph["summary"]["status"], "ready")
        self.assertEqual(
            graph["summary"]["target_certification_level"],
            "RDLLM-L48",
        )
        self.assertLess(
            graph["replay_order"].index("certification_report"),
            graph["replay_order"].index("provider_card"),
        )
        self.assertLess(
            graph["replay_order"].index("source_verification"),
            graph["replay_order"].index("source_confidence"),
        )
        self.assertLess(
            graph["replay_order"].index("revenue_allocation"),
            graph["replay_order"].index("finance_ledger"),
        )
        self.assertNotIn("hide-me", canonical_json(graph))
        self.assertFalse(graph["privacy"]["artifact_payloads_disclosed"])

        cyclic_graph = make_proof_dependency_graph(
            artifacts,
            dependencies=[
                *dependencies,
                {
                    "dependent": "certification_report",
                    "dependency": "provider_card",
                    "edge_class": "replay_dependency",
                    "reason": "cycle_probe",
                },
            ],
            issuer="test-issuer",
            created_at="2026-05-29T00:00:26Z",
            signing_secret="secret",
        )
        self.assertEqual(cyclic_graph["summary"]["status"], "failed")
        self.assertFalse(cyclic_graph["checks"]["replay_graph_acyclic"])

        assurance = make_assurance_bundle(
            [artifacts[0]],
            issuer="test-issuer",
            created_at="2026-05-29T00:00:26Z",
            signing_secret="secret",
        )
        publication_graph = make_proof_dependency_graph(
            [
                *artifacts,
                ("assurance_bundle", "assurance_bundle", assurance),
            ],
            dependencies=None,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:26Z",
            signing_secret="secret",
        )
        publication_edges = [
            row
            for row in publication_graph["dependencies"]
            if row["edge_class"] == "publication_commitment"
        ]
        self.assertEqual(
            {(row["dependent"], row["dependency"]) for row in publication_edges},
            {("assurance_bundle", "certification_report")},
        )

        private_graph = make_proof_dependency_graph(
            [
                *artifacts,
                (
                    "private_probe",
                    "unsafe_probe",
                    hashed("report_hash", {"prompt": "must fail"}),
                ),
            ],
            dependencies=dependencies,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:26Z",
            signing_secret="secret",
        )
        self.assertEqual(private_graph["summary"]["status"], "ready")
        self.assertEqual(
            verify_proof_dependency_graph(
                private_graph,
                [
                    *artifacts,
                    (
                        "private_probe",
                        "unsafe_probe",
                        hashed("report_hash", {"prompt": "must fail"}),
                    ),
                ],
                dependencies=dependencies,
                signing_secret="secret",
            ),
            [],
        )
        self.assertNotIn("must fail", canonical_json(private_graph))

        leaky_graph = deepcopy(graph)
        leaky_graph["artifacts"][0]["prompt"] = "leaked prompt"
        errors = verify_proof_dependency_graph(
            leaky_graph,
            artifacts,
            dependencies=dependencies,
            signing_secret="secret",
        )
        self.assertTrue(any("private fields" in error for error in errors))

        tampered = deepcopy(graph)
        tampered["replay_order"] = list(reversed(tampered["replay_order"]))
        errors = verify_proof_dependency_graph(
            tampered,
            artifacts,
            dependencies=dependencies,
            signing_secret="secret",
        )
        self.assertTrue(any("replay_order" in error or "hash" in error for error in errors))

