    def test_publication_monitor_tracks_append_only_artifact_snapshots(self) -> None:
        def hashed(field: str, payload: dict[str, object]) -> dict[str, object]:
            artifact = dict(payload)
            artifact[field] = hash_payload(artifact)
            return artifact

        artifacts_l48 = [
            (
                "provider_attribution_card",
                "provider_attribution_card",
                hashed("card_hash", {"provider": {"id": "provider:test"}}),
            ),
            (
                "certification_report",
                "certification_report",
                hashed("report_hash", {"summary": {"highest_level": "RDLLM-L48"}}),
            ),
            (
                "integration_profile",
                "integration_profile",
                hashed("profile_hash", {"summary": {"status": "ready"}}),
            ),
            (
                "response_envelope",
                "response_envelope",
                hashed("envelope_hash", {"summary": {"status": "verified"}}),
            ),
            (
                "assurance_bundle",
                "assurance_bundle",
                hashed("bundle_hash", {"summary": {"status": "ok"}}),
            ),
            (
                "proof_dependency_graph",
                "proof_dependency_graph",
                hashed("graph_hash", {"summary": {"status": "ready"}}),
            ),
        ]
        genesis = make_publication_monitor_report(
            artifacts_l48,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:27Z",
            signing_secret="secret",
        )
        self.assertEqual(
            verify_publication_monitor_report(
                genesis,
                artifacts_l48,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(genesis["summary"]["monitor_mode"], "genesis")
        self.assertEqual(genesis["summary"]["target_certification_level"], "RDLLM-L49")

        artifacts_l49 = [
            *artifacts_l48[:1],
            (
                "certification_report",
                "certification_report",
                hashed("report_hash", {"summary": {"highest_level": "RDLLM-L49"}}),
            ),
            *artifacts_l48[2:],
            (
                "private_probe",
                "diagnostic_report",
                hashed("report_hash", {"prompt": "secret prompt"}),
            ),
        ]
        appended = make_publication_monitor_report(
            artifacts_l49,
            previous_report=genesis,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:28Z",
            signing_secret="secret",
        )
        self.assertEqual(
            verify_publication_monitor_report(
                appended,
                artifacts_l49,
                previous_report=genesis,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(appended["summary"]["monitor_mode"], "append")
        self.assertEqual(appended["summary"]["checkpoint_count"], 2)
        self.assertIn("certification_report", appended["diff"]["changed_artifacts"])
        self.assertFalse(appended["diff"]["certification_regressed"])
        self.assertNotIn("secret prompt", canonical_json(appended))

        regressed_artifacts = [
            *artifacts_l48[:1],
            (
                "certification_report",
                "certification_report",
                hashed("report_hash", {"summary": {"highest_level": "RDLLM-L47"}}),
            ),
            *artifacts_l48[2:],
        ]
        regressed = make_publication_monitor_report(
            regressed_artifacts,
            previous_report=genesis,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:29Z",
            signing_secret="secret",
        )
        self.assertEqual(regressed["summary"]["status"], "failed")
        self.assertTrue(regressed["diff"]["certification_regressed"])

        tampered = deepcopy(appended)
        tampered["checkpoint_history"] = tampered["checkpoint_history"][1:]
        errors = verify_publication_monitor_report(
            tampered,
            artifacts_l49,
            previous_report=genesis,
            signing_secret="secret",
        )
        self.assertTrue(any("checkpoint" in error or "hash" in error for error in errors))

