    def test_trust_registry_binds_signers_witnesses_and_revocations(self) -> None:
        def signed(field: str, issuer: str, secret: str, payload: dict[str, object]) -> dict[str, object]:
            artifact = {"issuer": issuer, **payload}
            artifact[field] = hash_payload(artifact)
            artifact["signature"] = {
                "algorithm": "HMAC-SHA256",
                "issuer": issuer,
                "value": sign_payload(
                    {
                        key: value
                        for key, value in artifact.items()
                        if key not in {field, "signature"}
                    },
                    secret,
                ),
            }
            return artifact

        provider_secret = "provider-secret"
        artifacts = [
            (
                "provider_attribution_card",
                "provider_attribution_card",
                signed("card_hash", "provider:test", provider_secret, {"provider": {"id": "provider:test"}}),
            ),
            (
                "certification_report",
                "certification_report",
                signed(
                    "report_hash",
                    "provider:test",
                    provider_secret,
                    {"summary": {"highest_level": "RDLLM-L49", "status": "passed"}},
                ),
            ),
            (
                "integration_profile",
                "integration_profile",
                signed("profile_hash", "provider:test", provider_secret, {"summary": {"status": "ready"}}),
            ),
            (
                "response_envelope",
                "response_envelope",
                signed("envelope_hash", "provider:test", provider_secret, {"summary": {"status": "verified"}}),
            ),
            (
                "assurance_bundle",
                "assurance_bundle",
                signed("bundle_hash", "provider:test", provider_secret, {"summary": {"status": "ok"}}),
            ),
            (
                "proof_dependency_graph",
                "proof_dependency_graph",
                signed("graph_hash", "provider:test", provider_secret, {"summary": {"status": "ready"}}),
            ),
        ]
        monitor = make_publication_monitor_report(
            artifacts,
            issuer="provider:test",
            created_at="2026-05-29T00:00:40Z",
            signing_secret=provider_secret,
        )
        witnesses = [
            ("witness-alpha", "alpha-secret"),
            ("witness-bravo", "bravo-secret"),
            ("witness-charlie", "charlie-secret"),
        ]
        witness_report = make_publication_witness_report(
            [monitor],
            witnesses=witnesses,
            required_quorum=2,
            issuer="provider:test",
            created_at="2026-05-29T00:00:41Z",
            signing_secret=provider_secret,
        )
        registry_artifacts = [
            artifacts[0],
            ("publication_monitor", "publication_monitor", monitor),
            ("publication_witness", "publication_witness", witness_report),
        ]
        principals = [
            ("provider:test", "provider", provider_secret),
            ("witness-alpha", "witness", "alpha-secret"),
            ("witness-bravo", "witness", "bravo-secret"),
            ("witness-charlie", "witness", "charlie-secret"),
        ]
        rotations = [("provider:test", "provider", "old-provider-secret", provider_secret)]
        revoked_keys = [("provider:test", "provider", "old-provider-secret")]
        registry = make_trust_registry_report(
            registry_artifacts,
            principals=principals,
            publication_witnesses=[witness_report],
            rotations=rotations,
            revoked_keys=revoked_keys,
            issuer="provider:test",
            created_at="2026-05-29T00:00:42Z",
            signing_secret=provider_secret,
        )
        self.assertEqual(
            verify_trust_registry_report(
                registry,
                registry_artifacts,
                principals=principals,
                publication_witnesses=[witness_report],
                rotations=rotations,
                revoked_keys=revoked_keys,
                signing_secret=provider_secret,
            ),
            [],
        )
        self.assertEqual(registry["summary"]["status"], "ready")
        self.assertEqual(registry["summary"]["target_certification_level"], "RDLLM-L51")
        self.assertTrue(registry["checks"]["artifact_signatures_verified"])
        self.assertTrue(registry["checks"]["witness_signatures_verified"])
        self.assertTrue(registry["checks"]["rotations_link_active_new_keys"])
        self.assertNotIn(provider_secret, canonical_json(registry))
        self.assertNotIn("alpha-secret", canonical_json(registry))

        tampered_artifacts = deepcopy(registry_artifacts)
        tampered_artifacts[0][2]["signature"]["value"] = "bad"
        tampered_errors = verify_trust_registry_report(
            registry,
            tampered_artifacts,
            principals=principals,
            publication_witnesses=[witness_report],
            rotations=rotations,
            revoked_keys=revoked_keys,
            signing_secret=provider_secret,
        )
        self.assertTrue(any("artifact_bindings" in error or "hash" in error for error in tampered_errors))

        revoked_active = make_trust_registry_report(
            registry_artifacts,
            principals=principals,
            publication_witnesses=[witness_report],
            revoked_keys=[("provider:test", "provider", provider_secret)],
            issuer="provider:test",
            created_at="2026-05-29T00:00:43Z",
            signing_secret=provider_secret,
        )
        self.assertEqual(revoked_active["summary"]["status"], "failed")
        self.assertFalse(revoked_active["checks"]["artifact_signatures_verified"])

        wrong_witness_errors = verify_trust_registry_report(
            registry,
            registry_artifacts,
            principals=[
                ("provider:test", "provider", provider_secret),
                ("witness-alpha", "witness", "wrong-secret"),
                ("witness-bravo", "witness", "bravo-secret"),
                ("witness-charlie", "witness", "charlie-secret"),
            ],
            publication_witnesses=[witness_report],
            rotations=rotations,
            revoked_keys=revoked_keys,
            signing_secret=provider_secret,
        )
        self.assertTrue(any("witness" in error or "hash" in error for error in wrong_witness_errors))

    def test_certification_attestation_binds_report_to_trust_registry(self) -> None:
        certification = {
            "certification_version": "rdllm-certification/v1",
            "suite": "rdllm-reference-conformance",
            "issued_at": "2026-05-29T00:00:00Z",
            "implementation": {
                "engine": "rdllm-reference-python",
                "jurisdiction": "GLOBAL",
                "creator_pool_rate": "0.55",
                "top_k": 3,
                "corpus": "examples/sample_corpus.json",
                "restricted_corpus": "examples/restricted_corpus.json",
            },
            "summary": {
                "status": "passed",
                "case_count": 2,
                "passed": 2,
                "failed": 0,
                "score": 1.0,
                "highest_level": "RDLLM-L51",
            },
            "levels": {
                "RDLLM-L51": {
                    "passed": True,
                    "description": "Trust registry certified attribution.",
                    "requires": ["trust_registry", "publication_witness"],
                }
            },
            "cases": [
                {
                    "id": "publication_witness",
                    "title": "Publication witness",
                    "status": "passed",
                    "checks": {"quorum": True},
                    "artifacts": {"publication_witness_hash": stable_hash("witness")},
                    "errors": [],
                },
                {
                    "id": "trust_registry",
                    "title": "Trust registry",
                    "status": "passed",
                    "checks": {"registry": True},
                    "artifacts": {"trust_registry_hash": stable_hash("registry")},
                    "errors": [],
                },
            ],
        }
        certification["report_hash"] = hash_payload(certification)
        attestation = make_certification_attestation(
            certification,
            certifier_id="certifier:test",
            target_provider="provider:test",
            issuer="certifier:test",
            created_at="2026-05-29T00:00:50Z",
            signing_secret="certifier-secret",
        )
        self.assertEqual(
            verify_certification_attestation(
                attestation,
                certification,
                signing_secret="certifier-secret",
            ),
            [],
        )
        self.assertEqual(attestation["summary"]["target_certification_level"], "RDLLM-L52")
        self.assertEqual(attestation["summary"]["status"], "attested")
        self.assertEqual(
            attestation["subject"]["certification_report_hash"],
            certification["report_hash"],
        )
        self.assertFalse(attestation["privacy"]["certification_report_payload_embedded"])

        registry = make_trust_registry_report(
            [
                (
                    "certification_attestation",
                    "certification_attestation",
                    attestation,
                )
            ],
            principals=[("certifier:test", "certifier", "certifier-secret")],
            issuer="certifier:test",
            created_at="2026-05-29T00:00:51Z",
            signing_secret="certifier-secret",
        )
        self.assertEqual(
            verify_trust_registry_report(
                registry,
                [
                    (
                        "certification_attestation",
                        "certification_attestation",
                        attestation,
                    )
                ],
                principals=[("certifier:test", "certifier", "certifier-secret")],
                signing_secret="certifier-secret",
            ),
            [],
        )
        self.assertTrue(registry["artifact_bindings"][0]["signature_verified"])
        self.assertTrue(registry["artifact_bindings"][0]["signer_registered"])

        tampered = deepcopy(certification)
        tampered["summary"] = dict(tampered["summary"])
        tampered["summary"]["highest_level"] = "RDLLM-L50"
        drift_errors = verify_certification_attestation(
            attestation,
            tampered,
            signing_secret="certifier-secret",
        )
        self.assertTrue(any("report" in error or "hash" in error for error in drift_errors))

        tampered_attestation = deepcopy(attestation)
        tampered_attestation["signature"]["value"] = "bad"
        signature_errors = verify_certification_attestation(
            tampered_attestation,
            certification,
            signing_secret="certifier-secret",
        )
        self.assertTrue(any("signature" in error for error in signature_errors))

