    def test_counterfactual_report_replays_source_ablation(self) -> None:
        creator = Creator("owner", "Owner", "acct_owner")
        decoy_creator = Creator("decoy", "Decoy", "acct_decoy")
        source = Work(
            "credited-source",
            creator.creator_id,
            "Credited Source",
            (
                "Counterfactual reports remove a credited source, replay the same "
                "prompt and answer, and verify that source credit and payout move "
                "when the source is absent."
            ),
        )
        decoy = Work(
            "near-decoy",
            decoy_creator.creator_id,
            "Near Decoy",
            (
                "A museum catalog describes stone kilns, pottery glaze labels, and "
                "archival shelf numbers for a ceramics exhibit."
            ),
        )
        engine = RoyaltyDrivenLLM([creator, decoy_creator], [source, decoy], top_k=1)
        event = engine.attribute_text(
            "How can an attribution system prove the credited source mattered?",
            source.content,
            gross_revenue=Decimal("1.00"),
        )
        report = make_counterfactual_report(
            event,
            engine,
            issuer="test-issuer",
            created_at="2026-05-29T00:00:17Z",
            signing_secret="secret",
        )

        self.assertEqual(
            verify_counterfactual_report(
                report,
                event,
                engine,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(
            report["report_version"],
            "rdllm-counterfactual-influence/v1",
        )
        self.assertEqual(report["summary"]["status"], "ready")
        self.assertEqual(report["summary"]["subject_work_count"], 1)
        self.assertEqual(report["summary"]["decisive_source_count"], 1)
        self.assertTrue(report["summary"]["all_sources_counterfactually_removed"])
        self.assertTrue(
            report["interventions"][0]["intervention"][
                "payout_reallocated_or_escrowed"
            ]
        )
        rendered = canonical_json(report)
        self.assertNotIn(source.content, rendered)
        self.assertNotIn(decoy.content, rendered)
        self.assertNotIn(event.prompt, rendered)
        self.assertNotIn(event.answer_text, rendered)

        tampered = deepcopy(report)
        tampered["summary"] = dict(tampered["summary"])
        tampered["summary"]["decisive_source_count"] = 0
        errors = verify_counterfactual_report(
            tampered,
            event,
            engine,
            signing_secret="secret",
        )
        self.assertTrue(any("hash" in error or "replay" in error for error in errors))

