    def test_citation_identity_rejects_fabricated_and_metadata_swapped_sources(self) -> None:
        citation_input = {
            "event": {
                "event_id": "evt_citation_identity_test",
                "event_hash": "evt_hash_citation_identity_test",
                "prompt_text": "How should AI footers avoid hallucinated citations?",
                "response_text": (
                    "AI footers should show only real citations whose metadata and "
                    "claim support resolve against authority records."
                ),
                "model_id": "model:test",
                "model_version": "2026-05",
            },
            "claims": [
                {
                    "claim_id": "claim_identity",
                    "claim_text": (
                        "AI footers should show only real citations whose metadata "
                        "and claim support resolve against authority records."
                    ),
                    "required_evidence_phrases": [
                        "real citations",
                        "metadata-swapped citations",
                        "public answer footer",
                    ],
                    "citation_ids": ["cite_verified", "cite_swapped", "cite_fake"],
                }
            ],
            "citations": [
                {
                    "citation_id": "cite_verified",
                    "work_id": "work_identity",
                    "chunk_id": "chunk_identity",
                    "creator_id": "creator_identity",
                    "title": "Citation Identity for Grounded AI Attribution",
                    "authors": ["Maya Shah", "Ilya Novak"],
                    "year": "2026",
                    "doi": "10.5555/rdllm.citation.identity",
                    "source_uri": "https://example.test/citation-identity",
                    "quoted_text": (
                        "Private excerpt: real citations and metadata-swapped "
                        "citations must be checked before a public answer footer."
                    ),
                },
                {
                    "citation_id": "cite_swapped",
                    "work_id": "work_swapped",
                    "chunk_id": "chunk_swapped",
                    "creator_id": "creator_swapped",
                    "title": "Synthetic Images and Attribution Markets",
                    "authors": ["Not Maya Shah"],
                    "year": "2025",
                    "doi": "10.5555/rdllm.citation.identity",
                    "source_uri": "https://example.test/swapped",
                    "quoted_text": "Private excerpt: unrelated swapped metadata.",
                },
                {
                    "citation_id": "cite_fake",
                    "work_id": "work_fake",
                    "chunk_id": "chunk_fake",
                    "creator_id": "creator_fake",
                    "title": "A Nonexistent Study About Perfect AI Citations",
                    "authors": ["Fictional Author"],
                    "year": "2026",
                    "doi": "10.5555/fake.citation",
                    "source_uri": "https://example.test/fake",
                    "quoted_text": "Private excerpt: no authority record exists.",
                },
            ],
            "authority_records": [
                {
                    "authority_id": "doi:10.5555/rdllm.citation.identity",
                    "canonical_title": "Citation Identity for Grounded AI Attribution",
                    "canonical_authors": ["Maya Shah", "Ilya Novak"],
                    "year": "2026",
                    "identifiers": {"doi": "10.5555/rdllm.citation.identity"},
                    "source_uri": "https://example.test/citation-identity",
                    "abstract": (
                        "This record requires real citations to resolve against "
                        "authority records, blocks metadata-swapped citations, and "
                        "prevents unsupported sources from entering a public answer footer."
                    ),
                }
            ],
        }
        report = make_citation_identity_report(
            citation_input,
            gross_revenue=Decimal("1.00"),
            creator_pool_rate=Decimal("0.55"),
            issuer="test-issuer",
            created_at="2026-05-29T00:00:20Z",
            signing_secret="secret",
        )

        self.assertEqual(
            verify_citation_identity_report(
                report,
                citation_input,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(report["report_version"], "rdllm-citation-identity-report/v1")
        self.assertEqual(report["summary"]["target_certification_level"], "RDLLM-L69")
        self.assertEqual(report["summary"]["verified_citation_row_count"], 1)
        self.assertEqual(report["summary"]["metadata_mismatch_count"], 1)
        self.assertEqual(report["summary"]["fabricated_citation_count"], 1)
        self.assertTrue(report["checks"]["fabricated_citations_blocked"])
        self.assertTrue(report["checks"]["identifier_metadata_mismatches_blocked"])
        self.assertTrue(report["checks"]["verified_citations_have_canonical_footer"])
        self.assertTrue(report["checks"]["creator_pool_conserved"])
        self.assertEqual(len(report["canonical_footers"]), 1)
        self.assertTrue(
            all(
                row["decision"] == "citation_identity_escrow"
                for row in report["citation_rows"]
                if row["identity_status"]
                in {"fabricated_citation", "identifier_metadata_mismatch"}
            )
        )
        report_json = canonical_json(report)
        self.assertNotIn(citation_input["event"]["response_text"], report_json)
        self.assertNotIn(citation_input["authority_records"][0]["abstract"], report_json)

        tampered = deepcopy(report)
        tampered["canonical_footers"] = deepcopy(tampered["canonical_footers"])
        tampered["canonical_footers"][0]["identity_status"] = "fabricated_citation"
        errors = verify_citation_identity_report(
            tampered,
            citation_input,
            signing_secret="secret",
        )
        self.assertTrue(any("hash" in error or "replay" in error for error in errors))

