    def test_selective_disclosure_package_redacts_private_receipt_fields(self) -> None:
        event = self.engine.generate(
            "How should AI prove attribution?",
            gross_revenue=Decimal("1.00"),
        )
        receipt = make_attribution_receipt(
            event,
            issuer="test-issuer",
            model_id="test-model",
            model_version="2026-05-29",
            route_id="test-route",
            issued_at="2026-05-29T00:00:00Z",
            signing_secret="secret",
        )
        package = make_selective_disclosure_package(receipt)
        self.assertEqual(verify_selective_disclosure_package(package), [])
        self.assertEqual(
            verify_selective_disclosure_package(
                package,
                receipt,
                signing_secret="secret",
            ),
            [],
        )

        disclosed_paths = {leaf["path"] for leaf in package["disclosed"]}
        redacted_paths = {leaf["path"] for leaf in package["redacted"]}
        package_json = canonical_json(package)
        source_quote = receipt["payload"]["grounding"]["sources"][0]["quote"]

        self.assertEqual(
            package["public_receipt"]["privacy"]["disclosure_root"],
            receipt["payload"]["privacy"]["disclosure_root"],
        )
        self.assertNotIn("economics", package["public_receipt"])
        self.assertNotIn("grounding", package["public_receipt"])
        self.assertIn("claim_support", package["public_receipt"])
        self.assertTrue(all(not path.startswith("/economics/") for path in disclosed_paths))
        self.assertTrue(all(not path.startswith("/grounding/source_accesses/") for path in disclosed_paths))
        self.assertTrue(all(not path.endswith("/quote") for path in disclosed_paths))
        self.assertTrue(all(not path.endswith("/evidence_text") for path in disclosed_paths))
        self.assertTrue(any(path.startswith("/economics/") for path in redacted_paths))
        self.assertTrue(any(path.startswith("/grounding/source_accesses/") for path in redacted_paths))
        self.assertTrue(any(path.endswith("/quote") for path in redacted_paths))
        self.assertTrue(any(path.endswith("/evidence_text") for path in redacted_paths))
        self.assertNotIn(source_quote, package_json)
        self.assertFalse(
            any(leaf["path"].endswith("/evidence_text") for leaf in package["disclosed"])
        )
        self.assertFalse(
            any(leaf["path"] == "/economics/gross_revenue" for leaf in package["disclosed"])
        )

        tampered_event = dict(package)
        tampered_event["public_receipt"] = dict(package["public_receipt"])
        tampered_event["public_receipt"]["event"] = dict(package["public_receipt"]["event"])
        tampered_event["public_receipt"]["event"]["event_hash"] = "bad"
        self.assertTrue(
            any(
                "public receipt event" in error
                for error in verify_selective_disclosure_package(tampered_event)
            )
        )

        tampered_leaf = dict(package)
        tampered_leaf["disclosed"] = [dict(item) for item in package["disclosed"]]
        tampered_leaf["disclosed"][0]["value"] = "tampered"
        self.assertTrue(
            any(
                "disclosed leaf hash mismatch" in error
                for error in verify_selective_disclosure_package(tampered_leaf)
            )
        )

    def test_private_audit_challenge_opens_hidden_paths_without_public_text(self) -> None:
        event = self.engine.generate(
            "How should AI prove attribution?",
            gross_revenue=Decimal("1.00"),
        )
        receipt = make_attribution_receipt(
            event,
            issuer="test-issuer",
            model_id="test-model",
            model_version="2026-05-29",
            route_id="test-route",
            issued_at="2026-05-29T00:00:00Z",
            signing_secret="secret",
        )
        package = make_selective_disclosure_package(receipt)
        requested_paths = [
            "/economics/shares/0/payout",
            "/grounding/claims/0/evidence_text",
            "/grounding/source_accesses/0/access_id",
            "/rights/decisions/0/allowed",
        ]
        report = make_private_audit_challenge_report(
            package=package,
            receipt=receipt,
            requested_paths=requested_paths,
            auditor_id="auditor:test",
            challenge_nonce="nonce:test:2026-05-29",
            issuer="test-issuer",
            created_at="2026-05-29T00:00:00Z",
            signing_secret="secret",
        )

        self.assertEqual(
            verify_private_audit_challenge_report(
                report,
                package=package,
                receipt=receipt,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(
            verify_private_audit_challenge_report(
                report,
                package=package,
                signing_secret="secret",
            ),
            [],
        )
        self.assertEqual(report["summary"]["status"], "verified")
        self.assertEqual(report["summary"]["requested_path_count"], len(requested_paths))
        self.assertEqual(report["summary"]["missing_path_count"], 0)
        self.assertGreaterEqual(report["summary"]["redacted_path_count"], 3)
        self.assertTrue(
            all(row["checks"]["package_leaf_matches_private_leaf"] for row in report["challenge_rows"])
        )
        self.assertTrue(
            all(row["checks"]["private_value_disclosed_in_report"] is False for row in report["challenge_rows"])
        )
        report_json = canonical_json(report)
        self.assertNotIn(event.prompt, report_json)
        self.assertNotIn(event.answer_text, report_json)
        self.assertNotIn(event.claim_support[0].evidence_text, report_json)
        self.assertNotIn(self.engine.creators["arjun"].payout_account, report_json)
        self.assertTrue(report["privacy"]["paths_named_but_values_hidden"])

        tampered_nonce = deepcopy(report)
        tampered_nonce["audit_challenge"] = dict(tampered_nonce["audit_challenge"])
        tampered_nonce["audit_challenge"]["challenge_nonce"] = "nonce:replayed"
        self.assertTrue(
            any(
                "binding hash" in error or "opening commitment" in error or "hash" in error
                for error in verify_private_audit_challenge_report(
                    tampered_nonce,
                    package=package,
                    receipt=receipt,
                    signing_secret="secret",
                )
            )
        )

        tampered_opening = deepcopy(report)
        tampered_opening["challenge_rows"] = [dict(row) for row in report["challenge_rows"]]
        tampered_opening["challenge_rows"][0]["value_hash"] = "0" * 64
        self.assertTrue(
            any(
                "opening commitment" in error
                or "private receipt" in error
                or "row hash" in error
                for error in verify_private_audit_challenge_report(
                    tampered_opening,
                    package=package,
                    receipt=receipt,
                    signing_secret="secret",
                )
            )
        )

